INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028385e3c98b094176605e', '服务良好，设备高级，可惜入住当次房间打扫不确实（双床之间走道有点脏），床上被子里遗落一坨头发。厕所跟卫浴门用滑门共用挺特别的。', '["https://dimg04.c-ctrip.com/images/0236b2224wh2k8qq87026_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h2215gdpe67a8EA9B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-09-17', '花园大床房', '大床房', '商务出差', 63, 4.158883083359672, 0, 0.0, 552, 6.315358001522335, 7, '["客房服务", "房间设施", "卫生状况"]'::jsonb, '客房服务', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '服务良好，设备高级，可惜入住当次房间打扫不确实（双床之间走道有点脏），床上被子里', '服务良好，设备高级，可惜入住当次房间打扫不确实（双床之间走道有点脏），床上被子里遗落一坨头发。厕所跟卫浴门用滑门共用挺特别的。', '2023-09-17', 4, '客房服务');
