INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028385e3c98b0941766060', '我们的订单每天有2份早餐，但酒店记录只显示1份。我们必须出示trip.com的确认信息（幸好丈夫已经打印出来了，我们在订单中找不到了），他们检查了他们的记录是错误的。接待处的比利没有微笑，我认为他应该让我多加 1 份早餐（因为提前添加有折扣），但他没有这样做，让我花了半个小时来证明我应该吃 2 份早餐第二天早上。经理 Yannes 已经道歉并让我们在 VIP 休息室吃早餐（下午茶时间和欢乐时光也免费）。食物只是一般。女服务员问我食物还好吗，我说班尼迪克蛋面包太软了。然后她回答说通常人们不吃面包。你觉得她的回答很奇怪吗？
酒店很宏伟，花园和池塘很漂亮，房间很舒适，但你可以听到隔壁房间的噪音。保洁阿姨笑容很好，很有礼貌。
非常靠近地铁站和点豆鸭餐厅。', '["https://dimg04.c-ctrip.com/images/0231012000bktkdy25DC8_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232p12000bktk2vnBA5D_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231f12000bktkke4BA55_R_150_150_R5_Q70_D.png"]'::jsonb, 3.5, 3, '2023-07-05', '花园大床房', '大床房', '情侣出游', 327, 5.793013608384144, 0, 0.0, 1, 0.6931471805599453, 8, '["前台服务", "餐饮设施", "安静程度"]'::jsonb, '前台服务', '餐饮设施', '安静程度', '未知酒店', '未知地点', '匿名', '我们的订单每天有2份早餐，但酒店记录只显示1份。我们必须出示trip.com的确', '我们的订单每天有2份早餐，但酒店记录只显示1份。我们必须出示trip.com的确认信息（幸好丈夫已经打印出来了，我们在订单中找不到了），他们检查了他们的记录是错误的。接待处的比利没有微笑，我认为他应该让我多加 1 份早餐（因为提前添加有折扣），但他没有这样做，让我花了半个小时来证明我应该吃 2 份早餐第二天早上。经理 Yannes 已经道歉并让我们在 VIP 休息室吃早餐（下午茶时间和欢乐时光也免费）。食物只是一般。女服务员问我食物还好吗，我说班尼迪克蛋面包太软了。然后她回答说通常人们不吃面包。你觉得她的回答很奇怪吗？
酒店很宏伟，花园和池塘很漂亮，房间很舒适，但你可以听到隔壁房间的噪音。保洁阿姨笑容很好，很有礼貌。
非常靠近地铁站和点豆鸭餐厅。', '2023-07-05', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028385e3c98b0941766061', '邻近地铁站，位置方便。最可惜嘅地方，系附近有工程比较嘈。酒店房间都算新净，舒服。下次会再来的，不错不错', '["https://dimg04.c-ctrip.com/images/0230g12000c4l8zjkC594_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235f12000c4l8s9a89D8_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235m12000c4l8zr32FB2_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232r12000c4l8sfbD908_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234o12000c4l8pgo06C0_R_150_150_R5_Q70_D.png"]'::jsonb, 4.5, 4, '2023-09-13', '红棉双床套房', '套房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 21, 3.091042453358316, 6, '["交通便利性", "安静程度", "整体满意度"]'::jsonb, '交通便利性', '安静程度', '整体满意度', '未知酒店', '未知地点', '匿名', '邻近地铁站，位置方便。最可惜嘅地方，系附近有工程比较嘈。酒店房间都算新净，舒服。', '邻近地铁站，位置方便。最可惜嘅地方，系附近有工程比较嘈。酒店房间都算新净，舒服。下次会再来的，不错不错', '2023-09-13', 4, '交通便利性');
