INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028390e3c98b0941766067', '疫情后和丈夫一起陪老父返广州扫墓，选了入住著名的花园酒店两晚，由于需要加床，于是加钱提升了房间至套房，感觉物有所值，房间大以及干净整洁，而且隔音不错，见老父虽然疲倦但晚上仍睡得好，很难得。退房日早上到花园走了一圈，花园设计及打理得很好，鱼池锦鲤处处，生气勃勃；也到了三楼的博物馆走走，博物馆比我想像中规模大，设计也很到位，老父见到珍贵的旧相片也回忆到当年在广州的旧事呢！离开前到米芝连级中菜厅桃园馆享用了一餐值得回味的美食，十分赞！', '["https://dimg04.c-ctrip.com/images/0235q12000awtzg957335_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235012000awtztv92BAC_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0230t12000awtzbz9AF4B_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232212000awtzqaoE2E0_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233612000awv8go9FE67_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231512000awv82ahDEC6_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234u12000awv7mdy98CA_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236712000awv8ena92D5_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233l12000awv7z9dDFDD_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2023-04-11', '花园双床房', '双床房', '家庭亲子', 216, 5.37989735354046, 0, 0.0, 1, 0.6931471805599453, 9, '["房间设施", "整体满意度", "餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '疫情后和丈夫一起陪老父返广州扫墓，选了入住著名的花园酒店两晚，由于需要加床，于是', '疫情后和丈夫一起陪老父返广州扫墓，选了入住著名的花园酒店两晚，由于需要加床，于是加钱提升了房间至套房，感觉物有所值，房间大以及干净整洁，而且隔音不错，见老父虽然疲倦但晚上仍睡得好，很难得。退房日早上到花园走了一圈，花园设计及打理得很好，鱼池锦鲤处处，生气勃勃；也到了三楼的博物馆走走，博物馆比我想像中规模大，设计也很到位，老父见到珍贵的旧相片也回忆到当年在广州的旧事呢！离开前到米芝连级中菜厅桃园馆享用了一餐值得回味的美食，十分赞！', '2023-04-11', 5, '房间设施');
