INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028390e3c98b094176606c', '好似都无乜加价，平咗好多咁，我地原本拣每晚$1100 港币嘅大床普通房，去到check in 酒店帮我地升级去每晚千八蚊港币粤韵大床房，唔须要补差价，服务细心，房间装修新净，地方干净！所有酒店应该备有嘅物品都唔缺少。', '["https://dimg04.c-ctrip.com/images/0234p2215elxgkkxc0E50_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023462215elxgksn48D94_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c2224upamnrip6B81_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i2215elxgl82oB450_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023332234asnsqy407BD8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023322234asnsr5ts054E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i2224upamoeo01B9E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k2224upamomds76B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f2224upamou3kC87A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-09', '花园大床房', '大床房', '情侣出游', 108, 4.691347882229144, 0, 0.0, 12, 2.5649493574615367, 8, '["性价比", "前台服务", "卫生状况"]'::jsonb, '性价比', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '好似都无乜加价，平咗好多咁，我地原本拣每晚$1100 港币嘅大床普通房，去到ch', '好似都无乜加价，平咗好多咁，我地原本拣每晚$1100 港币嘅大床普通房，去到check in 酒店帮我地升级去每晚千八蚊港币粤韵大床房，唔须要补差价，服务细心，房间装修新净，地方干净！所有酒店应该备有嘅物品都唔缺少。', '2023-04-09', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028390e3c98b094176606d', '第一次入住，柜台特别安排中间的房间15楼，虽然旁边有新的地铁站在施工，但入住期间没有被施工噪音影响，连续住了三天非常舒适，非常推荐到广州的旅人可以入住，交通便利。早餐基本的都有，环境干净，吃饱还可以到外面的花园瀑布散步走走景色优美。', '["https://dimg04.c-ctrip.com/images/0233m2234atyllqn45683_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023522224uqlfj774194D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w2215en89gnr421A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f2215en89h36o3199_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l2234atylmt80FE11_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e2224uqlfk9s114E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023312215en89hqc1592D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n2215en89i5rkD686_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-13', '花园大床房', '大床房', '家庭亲子', 116, 4.762173934797756, 0, 0.0, 5, 1.791759469228055, 8, '["整体满意度", "交通便利性", "安静程度"]'::jsonb, '整体满意度', '交通便利性', '安静程度', '未知酒店', '未知地点', '匿名', '第一次入住，柜台特别安排中间的房间15楼，虽然旁边有新的地铁站在施工，但入住期间', '第一次入住，柜台特别安排中间的房间15楼，虽然旁边有新的地铁站在施工，但入住期间没有被施工噪音影响，连续住了三天非常舒适，非常推荐到广州的旅人可以入住，交通便利。早餐基本的都有，环境干净，吃饱还可以到外面的花园瀑布散步走走景色优美。', '2023-04-13', 5, '整体满意度');
