INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028390e3c98b094176606f', '房间很舒适，但是床有点太软，而且外面有工程进行中，嘈音很大，不得不要求换房间，幸好最后也安排了。早餐种类可以，但餐厅装修很土。所有的职员都十分有礼，值得再次入住。', '["https://dimg04.c-ctrip.com/images/0231v2215emazidgh861D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q2215emazidggE67F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o2234at1bnvs10BC5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023692224upo5l4m8EA46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023592215emazidgi0F9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p2215emazil68B1CE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-04-10', '花园大床房', '大床房', '情侣出游', 81, 4.406719247264253, 0, 0.0, 39, 3.688879454113936, 8, '["安静程度", "房间设施", "整体满意度"]'::jsonb, '安静程度', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间很舒适，但是床有点太软，而且外面有工程进行中，嘈音很大，不得不要求换房间，幸', '房间很舒适，但是床有点太软，而且外面有工程进行中，嘈音很大，不得不要求换房间，幸好最后也安排了。早餐种类可以，但餐厅装修很土。所有的职员都十分有礼，值得再次入住。', '2023-04-10', 4, '安静程度');
