INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802839be3c98b0941766071', '酒店位置十分方便，酒店设施非常完善，房间内环境卫生令人满意，酒店内食肆的质素非常高！服务人态度亦殷勤！值得推荐！', '["https://dimg04.c-ctrip.com/images/0234x2224ux6pn26p1D1F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-29', '花园大床房', '大床房', '商务出差', 56, 4.04305126783455, 0, 0.0, 9, 2.302585092994046, 7, '["交通便利性", "整体满意度", "餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店位置十分方便，酒店设施非常完善，房间内环境卫生令人满意，酒店内食肆的质素非常', '酒店位置十分方便，酒店设施非常完善，房间内环境卫生令人满意，酒店内食肆的质素非常高！服务人态度亦殷勤！值得推荐！', '2023-04-29', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802839be3c98b0941766072', '大堂很漂亮，有中国新年装饰。
预订细节有误会，但很快就处理了。我认为这是预期的。
有意见说设施老旧，但干净舒适。房间卫生很难维护，所以是一流的酒店。
酒店的早餐是自助式的，一切都很美味。
酒店内的点心餐厅非常好吃，我们只能在这家酒店才能品尝到。脆皮特别好吃。
另外,是想住在的酒店。', '["https://dimg04.c-ctrip.com/images/0234312000ai74302A2E5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000ai72xw20F8E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000ai7358c7183_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-25', '红棉双床套房', '套房', '家庭亲子', 141, 4.955827057601261, 0, 0.0, 24, 3.218875824868201, 7, '["餐饮设施", "整体满意度", "卫生状况"]'::jsonb, '餐饮设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '大堂很漂亮，有中国新年装饰。', '大堂很漂亮，有中国新年装饰。
预订细节有误会，但很快就处理了。我认为这是预期的。
有意见说设施老旧，但干净舒适。房间卫生很难维护，所以是一流的酒店。
酒店的早餐是自助式的，一切都很美味。
酒店内的点心餐厅非常好吃，我们只能在这家酒店才能品尝到。脆皮特别好吃。
另外,是想住在的酒店。', '2023-01-25', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802839be3c98b0941766073', '在广州生活了快30年；第一次入住这个在家门口的老牌酒店，本次作为生日的staycation旅程，总体感觉还是比较满意的，主要想提及一下下面几个方面：
一、服务
1.入住时因为是岭南金卡会员，主动升级了一个小套房和告知有一位行政酒廊礼遇，前台工作的同事也很热情；
2.作为第一次体验行政酒廊的‘大乡里’来说，特别要感谢及点赞酒廊里面的同事Cons小哥哥，服务非常周到，同时因为到达时间已经是happyhour了，Cons还特地来写了一张邀请函，说明天我们退房后还可以来体验下午茶，很贴心??
3.晚上因为胃部不适外卖了药品，因为实在走不动，致电前台希望能有同事帮忙送一下到房间，结果遭到冰冷拒绝，还是需要拖着不舒服的身体到楼下去取，这个是令我的体验感大打折扣的。
二、房间
升级了小套房，比较古色古香岭南风格的设计很舒适，但是希望酒店还能在细节方面再注意一下：
1.床脚其中一个角的床单没有折好，令人感觉有点‘唠搞’
2.客厅的地毯上估计是一些边角位吸尘没有很注意到，有一些饼干屑一样的东西，希望可以注意一下
3.被套上有一小点红色，但是看起来不像血渍故没有让客服去处理
4.放置备品的小架子希望客房人员注意一下彻底的清洁，虽然小抽屉拉出来拉一半看不到，可是牙刷拿出来发现小抽屉靠里面的位置居然残留上一位客人用过的剃须刀外包装纸盒，究竟有没有认真清洁这个我真的要打一个问号了。
总之，此行总体体验感还是很不错的，服务很加分特别是Cons小哥哥真的令我感到像老朋友一样的窝心', '["https://dimg04.c-ctrip.com/images/0234k12000ag3gxk164FA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000ag3gtjy6105_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000ag3fuijC0EF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-15', '花园大床房', '大床房', '情侣出游', 636, 6.456769655572163, 0, 0.0, 2, 1.0986122886681098, 9, '["客房服务", "前台服务", "卫生状况"]'::jsonb, '客房服务', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '在广州生活了快30年；第一次入住这个在家门口的老牌酒店，本次作为生日的stayc', '在广州生活了快30年；第一次入住这个在家门口的老牌酒店，本次作为生日的staycation旅程，总体感觉还是比较满意的，主要想提及一下下面几个方面：
一、服务
1.入住时因为是岭南金卡会员，主动升级了一个小套房和告知有一位行政酒廊礼遇，前台工作的同事也很热情；
2.作为第一次体验行政酒廊的‘大乡里’来说，特别要感谢及点赞酒廊里面的同事Cons小哥哥，服务非常周到，同时因为到达时间已经是happyhour了，Cons还特地来写了一张邀请函，说明天我们退房后还可以来体验下午茶，很贴心??
3.晚上因为胃部不适外卖了药品，因为实在走不动，致电前台希望能有同事帮忙送一下到房间，结果遭到冰冷拒绝，还是需要拖着不舒服的身体到楼下去取，这个是令我的体验感大打折扣的。
二、房间
升级了小套房，比较古色古香岭南风格的设计很舒适，但是希望酒店还能在细节方面再注意一下：
1.床脚其中一个角的床单没有折好，令人感觉有点‘唠搞’
2.客厅的地毯上估计是一些边角位吸尘没有很注意到，有一些饼干屑一样的东西，希望可以注意一下
3.被套上有一小点红色，但是看起来不像血渍故没有让客服去处理
4.放置备品的小架子希望客房人员注意一下彻底的清洁，虽然小抽屉拉出来拉一半看不到，可是牙刷拿出来发现小抽屉靠里面的位置居然残留上一位客人用过的剃须刀外包装纸盒，究竟有没有认真清洁这个我真的要打一个问号了。
总之，此行总体体验感还是很不错的，服务很加分特别是Cons小哥哥真的令我感到像老朋友一样的窝心', '2023-01-15', 4, '客房服务');
