INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176608c', '酒店前台YOLO服务好！！酒店各项设施也很不错，入住还有欢迎水果！景观很不错，推荐入住，酒店地理位置特别好，去各个景点都很方便！早餐多選擇，非常好味??', '["https://dimg04.c-ctrip.com/images/0233v224x8zz3fk5g610B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i224x8zz25ttp2991_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w224x8zz1y6tp5FE6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-18', '花园大床房', '大床房', '家庭亲子', 76, 4.343805421853684, 0, 0.0, 6, 1.9459101490553128, 7, '["前台服务", "景观/朝向", "交通便利性"]'::jsonb, '前台服务', '景观/朝向', '交通便利性', '未知酒店', '未知地点', '匿名', '酒店前台YOLO服务好！！酒店各项设施也很不错，入住还有欢迎水果！景观很不错，推', '酒店前台YOLO服务好！！酒店各项设施也很不错，入住还有欢迎水果！景观很不错，推荐入住，酒店地理位置特别好，去各个景点都很方便！早餐多選擇，非常好味??', '2025-03-18', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176608d', '老牌子的酒店，交通方便，旁边就有地铁，车到酒店服务人员帮助拿行李，前台帅小伙帮忙升级一间房间，虽然过程有点慢，但对房间还是非常满意，毕竟过年人多，酒店管理还是挺有序的。早晨的瀑布歺厅早歺挺不错，一边吃饭一边看着瀑布，心情非常好，参观了酒店的博物馆，了解酒店发展史，真的不错，总之游广州住花园酒店是个很好的选择。', '["https://dimg04.c-ctrip.com/images/0235d12000i91ehiuE1E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000i9173a31B3D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000i920h0984AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000i91np9u41BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-02', '花园双床房', '双床房', '家庭亲子', 155, 5.049856007249537, 0, 0.0, 54, 4.007333185232471, 8, '["交通便利性", "前台服务", "餐饮设施"]'::jsonb, '交通便利性', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '老牌子的酒店，交通方便，旁边就有地铁，车到酒店服务人员帮助拿行李，前台帅小伙帮忙', '老牌子的酒店，交通方便，旁边就有地铁，车到酒店服务人员帮助拿行李，前台帅小伙帮忙升级一间房间，虽然过程有点慢，但对房间还是非常满意，毕竟过年人多，酒店管理还是挺有序的。早晨的瀑布歺厅早歺挺不错，一边吃饭一边看着瀑布，心情非常好，参观了酒店的博物馆，了解酒店发展史，真的不错，总之游广州住花园酒店是个很好的选择。', '2025-02-02', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176608e', '来广州五天四晚，全住在广州花园酒店，前两天红棉大床房，后两天行程临时改变退了后面的酒店想这边续住只有绿央双床了，酒店所有的服务都很好，入住送了精致的点心，携程钻石关联了金卡赠送了早餐和行政酒廊，行政酒廊有个外国面孔的女孩非常热情，酒店有个博物馆可以进去看看，小花园不大但是打理的不错，红棉大床房我和家人都非常满意，干净宽敞没有异味房间也比较漂亮，但是换到绿央觉得有些糟糕，房间很小，设施陈旧，有霉味，这些我也能理解毕竟老酒店，但是绿央房间的玻璃非常的脏，这个是我理解不了的，酒店窗户开的话需要签免责声明，我不理解为啥不能给装上限位器，一开始住红棉楼层比较高我也没敢开，但是绿央霉味太重孩子进去就老咳嗽，我就叫把窗户打开了，但是就很操心，实际我订房后面绿央比红棉每天还贵600+，红棉推荐，绿央房强烈不推荐。', '["https://dimg04.c-ctrip.com/images/0230b12000i7j121a812E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000i7jjtzw978E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000i7j9a58A7DF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000i7ioem70D7C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000i7ip1u5CB76_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-01', '红棉大床套房', '套房', '家庭亲子', 353, 5.869296913133774, 0, 0.0, 10, 2.3978952727983707, 9, '["房间设施", "整体满意度", "价格合理性"]'::jsonb, '房间设施', '整体满意度', '价格合理性', '未知酒店', '未知地点', '匿名', '来广州五天四晚，全住在广州花园酒店，前两天红棉大床房，后两天行程临时改变退了后面', '来广州五天四晚，全住在广州花园酒店，前两天红棉大床房，后两天行程临时改变退了后面的酒店想这边续住只有绿央双床了，酒店所有的服务都很好，入住送了精致的点心，携程钻石关联了金卡赠送了早餐和行政酒廊，行政酒廊有个外国面孔的女孩非常热情，酒店有个博物馆可以进去看看，小花园不大但是打理的不错，红棉大床房我和家人都非常满意，干净宽敞没有异味房间也比较漂亮，但是换到绿央觉得有些糟糕，房间很小，设施陈旧，有霉味，这些我也能理解毕竟老酒店，但是绿央房间的玻璃非常的脏，这个是我理解不了的，酒店窗户开的话需要签免责声明，我不理解为啥不能给装上限位器，一开始住红棉楼层比较高我也没敢开，但是绿央霉味太重孩子进去就老咳嗽，我就叫把窗户打开了，但是就很操心，实际我订房后面绿央比红棉每天还贵600+，红棉推荐，绿央房强烈不推荐。', '2025-02-01', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176608f', '春节期间订了三间房住了四晚，新春南国醒狮很有特色，酒店大堂布置的很好，还有新春手工活动。
