酒店的博物馆很值得参观，孩子参观后还用了相关内容做了寒假作业', '["https://dimg04.c-ctrip.com/images/0231o12000iby9roz1140_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000ibyjw5x1982_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000ibyf573B90F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 131, 4.882801922586371, 0, 0.0, 13, 2.6390573296152584, 8, '["客房服务", "餐饮设施", "整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '春节期间订了三间房住了四晚，新春南国醒狮很有特色，酒店大堂布置的很好，还有新春手', '春节期间订了三间房住了四晚，新春南国醒狮很有特色，酒店大堂布置的很好，还有新春手工活动。
房间打扫的是一个尼泊尔小姑娘，虽然语言不通，但是她态度非常好
自助早餐一层，三层，三十层都可以，种类基本上一样
酒店的博物馆很值得参观，孩子参观后还用了相关内容做了寒假作业', '2025-02-05', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766091', '酒店在市中心出行很方便门口就是地铁站。服务人员很热情友好。但是首日入住晚上准备睡觉时被床上用品卫生条件吓一跳有点怀疑清洁人员是否退房以后更换床上用品。发霉严重如果没有发现会影响身体健康。希望五星级酒店注重床品卫生
卫生：床品发霉', '["https://dimg04.c-ctrip.com/images/0231o12000i4hw77hAAE2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2025-01-28', '花园双床房', '双床房', '家庭亲子', 114, 4.74493212836325, 0, 0.0, 11, 2.4849066497880004, 8, '["卫生状况", "前台服务", "交通便利性"]'::jsonb, '卫生状况', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '酒店在市中心出行很方便门口就是地铁站。服务人员很热情友好。但是首日入住晚上准备睡', '酒店在市中心出行很方便门口就是地铁站。服务人员很热情友好。但是首日入住晚上准备睡觉时被床上用品卫生条件吓一跳有点怀疑清洁人员是否退房以后更换床上用品。发霉严重如果没有发现会影响身体健康。希望五星级酒店注重床品卫生
卫生：床品发霉', '2025-01-28', 3, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766092', '多年前就有去花园酒店住一住的想法，这次带着老的小的终于来了，虽然我们就生活在广州。可能还没到过年，酒店帮我把大床换成双床了，赞！去到办理入住，等了有一会，不过还是值得的。酒店环境不错，最惊喜的是她家的后花园，在寸土寸金的环市路，还有这一方天地，很棒！再说吃的这方面，感觉不达预期，特别是荔湾亭，出品和价格不成正比，只是盛名在外吧！', '["https://dimg04.c-ctrip.com/images/0236p12000ia5vlhlB322_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000ia6mh5h915A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000ia7560l2FC2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-03', '红棉大床套房', '套房', '家庭亲子', 165, 5.111987788356544, 0, 0.0, 14, 2.70805020110221, 8, '["整体满意度", "周边配套", "性价比"]'::jsonb, '整体满意度', '周边配套', '性价比', '未知酒店', '未知地点', '匿名', '多年前就有去花园酒店住一住的想法，这次带着老的小的终于来了，虽然我们就生活在广州', '多年前就有去花园酒店住一住的想法，这次带着老的小的终于来了，虽然我们就生活在广州。可能还没到过年，酒店帮我把大床换成双床了，赞！去到办理入住，等了有一会，不过还是值得的。酒店环境不错，最惊喜的是她家的后花园，在寸土寸金的环市路，还有这一方天地，很棒！再说吃的这方面，感觉不达预期，特别是荔湾亭，出品和价格不成正比，只是盛名在外吧！', '2025-02-03', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766094', '是我喜欢的酒店风格没错了。酒店的位置很好，就在沙面岛上，无论是欣赏珠江的风光还是探访充满风情的沙面建筑群都特别方便。值得表扬的还有吃白天鹅的早茶太方便啦，住酒店可以直接预约，不用排队。', '["https://dimg04.c-ctrip.com/images/0234g12000iarwfm64663_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000iasiuq9BE06_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236t12000iarqqtw43BF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 92, 4.532599493153256, 0, 0.0, 4, 1.6094379124341005, 9, '["周边配套", "整体满意度"]'::jsonb, '周边配套', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '是我喜欢的酒店风格没错了。酒店的位置很好，就在沙面岛上，无论是欣赏珠江的风光还是', '是我喜欢的酒店风格没错了。酒店的位置很好，就在沙面岛上，无论是欣赏珠江的风光还是探访充满风情的沙面建筑群都特别方便。值得表扬的还有吃白天鹅的早茶太方便啦，住酒店可以直接预约，不用排队。', '2025-02-04', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766095', '酒店房间宽敞设施完善，节日气氛浓厚。本来计划一天后去长隆玩住长隆附近，但是孩子们超级喜欢这里的瀑布和花园，早餐美食，又续住两天，游玩长隆后也要回来。下次来广州还住这??', '["https://dimg04.c-ctrip.com/images/0234712000iid111h121E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000iicpuqr68FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231h12000iick06r8ACC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-13', '花园双床房', '双床房', '家庭亲子', 84, 4.442651256490317, 0, 0.0, 11, 2.4849066497880004, 7, '["整体满意度", "餐饮设施", "房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '酒店房间宽敞设施完善，节日气氛浓厚。本来计划一天后去长隆玩住长隆附近，但是孩子们', '酒店房间宽敞设施完善，节日气氛浓厚。本来计划一天后去长隆玩住长隆附近，但是孩子们超级喜欢这里的瀑布和花园，早餐美食，又续住两天，游玩长隆后也要回来。下次来广州还住这??', '2025-02-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766096', '服务满分，帮我两个房间都升级了套房，早餐也送了一份小朋友的。吃的很满意！那一层有个年轻阿姨打扫，房门出出进进都能遇到，打扫的很干净。花园又大又漂亮。', '["https://dimg04.c-ctrip.com/images/0230812000in5knr396C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000in5nal74656_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000in53ayyF465_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000in51ci46866_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-20', '花园双床房', '双床房', '家庭亲子', 74, 4.31748811353631, 0, 0.0, 23, 3.1780538303479458, 8, '["前台服务", "客房服务", "餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '服务满分，帮我两个房间都升级了套房，早餐也送了一份小朋友的。吃的很满意！那一层有', '服务满分，帮我两个房间都升级了套房，早餐也送了一份小朋友的。吃的很满意！那一层有个年轻阿姨打扫，房门出出进进都能遇到，打扫的很干净。花园又大又漂亮。', '2025-02-20', 5, '前台服务');
