INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176609d', '酒店的环境非常优美，让人流连忘返。客房宽敞明亮，家具摆设高雅舒适，让人倍感温馨。酒店还提供免费的无线网络服务，让我们在旅途中可以随时保持联系。酒店的位置也非常便利，距离景点和商业区都很近，我们可以在闲暇之余轻松游览城市的各个角落。此外，酒店的餐饮也是一大亮点，各种美食应有尽有，让人垂涎欲滴。总之，这家酒店给我们留下了深刻的印象，我们会极力推荐给我的朋友和家人！', '["https://dimg04.c-ctrip.com/images/0233n12000hgoxkw32955_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000hgp8lwa30B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000hgpdl1p3D68_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-28', '花园大床房', '大床房', '朋友出游', 181, 5.204006687076795, 0, 0.0, 74, 4.31748811353631, 9, '["整体满意度", "房间设施", "周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套', '未知酒店', '未知地点', '匿名', '酒店的环境非常优美，让人流连忘返。客房宽敞明亮，家具摆设高雅舒适，让人倍感温馨。', '酒店的环境非常优美，让人流连忘返。客房宽敞明亮，家具摆设高雅舒适，让人倍感温馨。酒店还提供免费的无线网络服务，让我们在旅途中可以随时保持联系。酒店的位置也非常便利，距离景点和商业区都很近，我们可以在闲暇之余轻松游览城市的各个角落。此外，酒店的餐饮也是一大亮点，各种美食应有尽有，让人垂涎欲滴。总之，这家酒店给我们留下了深刻的印象，我们会极力推荐给我的朋友和家人！', '2024-12-28', 5, '整体满意度');
