INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660ba', '住宿体验非常好，各个岗位的服务人员都非常专业热情。商务酒廊很多人来打卡，就说明了室内的瀑布花园很得人心。老牌五星还是靠谱！', '["https://dimg04.c-ctrip.com/images/0232r12000h0n7lblF9E5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-03', '花园双床房', '双床房', '家庭亲子', 61, 4.127134385045092, 0, 0.0, 5, 1.791759469228055, 7, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '住宿体验非常好，各个岗位的服务人员都非常专业热情。商务酒廊很多人来打卡，就说明了', '住宿体验非常好，各个岗位的服务人员都非常专业热情。商务酒廊很多人来打卡，就说明了室内的瀑布花园很得人心。老牌五星还是靠谱！', '2024-12-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660bb', '环境和酒店的大堂设计很好，风格独特，不过人员服务很不专业，本来节假日期间，下午2点左右就是入住高峰，应该有这样的应急服务准备，check in 速度很慢，等好久，好不容易等到了，填了一堆表后，竟然告诉我房间没打扫好，时间需要1个半小时，只能把行李放下，先去其他地方逛逛，回来后行李还要自己拿到房间不说，第二天原房续住，只要重新刷下卡就行了，前台穿亮片衣服的小姐姐竟然还叫我和人家check in 的一起再排队，我就火了，重新找了个工作人员，人家帮我重新刷了个卡，2分钟的事，如果前台人员不熟悉流程，应该加强员工的培训，而不是傻傻不懂，耽误别人时间，酒店人员的素质和专业才是最看重的，虚有其表，慢慢就会落寞！', '["https://dimg04.c-ctrip.com/images/0230c12000fzpft1tE280_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000fzp5nav4086_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-10-05', '花园大床房', '大床房', '家庭亲子', 303, 5.717027701406222, 1, 0.6931471805599453, 14, 2.70805020110221, 9, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '环境和酒店的大堂设计很好，风格独特，不过人员服务很不专业，本来节假日期间，下午2', '环境和酒店的大堂设计很好，风格独特，不过人员服务很不专业，本来节假日期间，下午2点左右就是入住高峰，应该有这样的应急服务准备，check in 速度很慢，等好久，好不容易等到了，填了一堆表后，竟然告诉我房间没打扫好，时间需要1个半小时，只能把行李放下，先去其他地方逛逛，回来后行李还要自己拿到房间不说，第二天原房续住，只要重新刷下卡就行了，前台穿亮片衣服的小姐姐竟然还叫我和人家check in 的一起再排队，我就火了，重新找了个工作人员，人家帮我重新刷了个卡，2分钟的事，如果前台人员不熟悉流程，应该加强员工的培训，而不是傻傻不懂，耽误别人时间，酒店人员的素质和专业才是最看重的，虚有其表，慢慢就会落寞！', '2024-10-05', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660bc', '酒店很多外国人，果然是广州的改革开放排头兵。
优点很多，例如花园很好，很多名暖来拍照打卡。缺点就是地下车库的入口位不好找，被另外的牌子混淆了。老地下车库了，没有直接连到酒店大楼，拿着行李有点麻烦，且没有遮雨棚，这一点实在不应该。不过免费升级了套房，给了点安慰。', '["https://dimg04.c-ctrip.com/images/0232312000g5gtyqiB1F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000g5haljg8D19_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000g5hbz99DE7D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000g5hbeamB886_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000g5h6sdc1659_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000g5h3uewB583_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000g5hc2onD86F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-15', '花园大床房', '大床房', '商务出差', 130, 4.875197323201151, 0, 0.0, 141, 4.955827057601261, 8, '["公共设施", "交通便利性", "整体满意度"]'::jsonb, '公共设施', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店很多外国人，果然是广州的改革开放排头兵。', '酒店很多外国人，果然是广州的改革开放排头兵。
