INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660bf', '广州花园酒店非常大非常多的打卡点，听说是有26个这样子哈哈哈
一个酒店里居然还有博物馆，这一点让我非常震惊
然后后花园也有一个二十几米高的瀑布，在广州这个地段 一个酒店能有这么一个这么大的后花园 让我感觉这个酒店挺牛的
然后这个酒店最让我感觉舒适的就是30楼的行政酒廊了
30楼的环境很不错，服务更是锦上添花
Echo的服务态度很好，非常的贴心，我们是下午茶过来的，然后Echo她也非常热情的邀请我过来这里是下午五点开始的欢乐时光，然后我在六点多这样子过来了，欢乐时光比下午茶的食物要丰富一些
然后Carrie、beryle也非常热情 对小朋友很贴心，详细的了酒店好多的打卡点，推荐我们带小朋友去广州花园酒店酒店的博物馆、旋转木楼梯、大堂红楼梦壁画那里看看
我们趁着雨停的时候我们也去了后花园打卡那些植物领取相对应地小礼品，广州花园酒店这个活动确实不错，挺适合亲子互动的哈哈哈
时隔六年来广州玩，这次的酒店选择非常棒，体验很好，行政酒廊的小姐姐们也都让我们感受到温暖
下次再来广州还会选择你们广州的花园酒店', '["https://dimg04.c-ctrip.com/images/0236d12000f790epwB8AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000f78v3zj1EE2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000f78zd8l4E9C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000f78xjctB331_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000f78xwa37339_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000f797nrp26D0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000f793epw3681_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000f78uyak5037_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000f78uyamBBC9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-21', '花园大床房', '大床房', '家庭亲子', 459, 6.131226489483141, 1, 0.6931471805599453, 12, 2.5649493574615367, 9, '["公共设施", "前台服务", "整体满意度"]'::jsonb, '公共设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '广州花园酒店非常大非常多的打卡点，听说是有26个这样子哈哈哈', '广州花园酒店非常大非常多的打卡点，听说是有26个这样子哈哈哈
