INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660cb', '一个月第二次入住，这次真的没有前一次的好，尤其是订房题为城央绿意名字根本有误导之嫌？！同时下单只是前后之分。第一次订只说是普通房间8百多，再订时看到城央绿意标志还贵很多9百多，以为是更好一点的外景，没想到还不如第一次，房间设施陈旧不堪，20楼服务没有21楼的贴心，住三个晚上咖啡杯没换、连加咖啡机里面的东西也没有清理;厕所板摇摇晃晃;洗漱台去水口流得很慢，到最后还有很吓人的去水声音！总之，第二次的入住不尽人意', '["https://dimg04.c-ctrip.com/images/0230912000fcwp4hlA8AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000fcwn6g0E654_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000fcwqfv7FF2A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-02', '城央绿意双床房', '双床房', '家庭亲子', 205, 5.327876168789581, 0, 0.0, 3, 1.3862943611198906, 9, '["房间设施", "客房服务"]'::jsonb, '房间设施', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '一个月第二次入住，这次真的没有前一次的好，尤其是订房题为城央绿意名字根本有误导之', '一个月第二次入住，这次真的没有前一次的好，尤其是订房题为城央绿意名字根本有误导之嫌？！同时下单只是前后之分。第一次订只说是普通房间8百多，再订时看到城央绿意标志还贵很多9百多，以为是更好一点的外景，没想到还不如第一次，房间设施陈旧不堪，20楼服务没有21楼的贴心，住三个晚上咖啡杯没换、连加咖啡机里面的东西也没有清理;厕所板摇摇晃晃;洗漱台去水口流得很慢，到最后还有很吓人的去水声音！总之，第二次的入住不尽人意', '2024-09-02', 5, '房间设施');
