INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660d5', '大堂装修豪华，服务到位，非常舒适', '["https://dimg04.c-ctrip.com/images/0235112000ifpqrjvE842_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231x12000ifpqxhy4FAF_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231d12000ifpqv1a08F5_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-02-10', '花园双床房', '双床房', '家庭亲子', 16, 2.833213344056216, 0, 0.0, 12, 2.5649493574615367, 4, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '大堂装修豪华，服务到位，非常舒适', '大堂装修豪华，服务到位，非常舒适', '2025-02-10', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660d6', '来广州首选花园酒店，住过好几次了还是非常满意！工作人员热情有礼，感谢Cecilia和Gillian，看到我们带小孩就给我们免费升级了房间～房间干净整洁，早餐品种比较丰富，味道很不错的。', '["https://dimg04.c-ctrip.com/images/0236b12000faxc77w62A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000faxaxonC3BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000faxd2jj4E46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000faxd2jl8132_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-30', '花园大床房', '大床房', '家庭亲子', 92, 4.532599493153256, 0, 0.0, 23, 3.1780538303479458, 8, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '来广州首选花园酒店，住过好几次了还是非常满意！工作人员热情有礼，感谢Cecili', '来广州首选花园酒店，住过好几次了还是非常满意！工作人员热情有礼，感谢Cecilia和Gillian，看到我们带小孩就给我们免费升级了房间～房间干净整洁，早餐品种比较丰富，味道很不错的。', '2024-08-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660d7', '作为广州本地人，我偶尔住酒店换换心情，常住的是MO，这次换了花园酒店，很是惊喜。花园是广州最老牌的五星酒店，改革开放后算是广州地标了，本地人无人不知，那时是外宾住的，当时还没有四季瑰丽MO。十年前，装修前我也住过，体验也不错。这次是装修后，升级了红棉套房，房间大，设计合理，床垫舒适，按这个价格来说，性价比极高了。服务方面，所有服务人员都很热情，有笑容，尤其多了很多印度服务生，那态度更好，笑得也灿烂。基本上，客人的要求有求必应，服务专业周到，我离开酒店遗漏钱包在保险柜，也马上联系，妥善处理，可以体会出来是正宗五星酒店的服务水平。早餐，4个餐厅，吃的也好。总体来说，这是家有品位，有品质，有文化底蕴的五星酒店，值得！', '["https://dimg04.c-ctrip.com/images/0231d12000f5lrv509B8F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-17', '城央绿意大床房', '大床房', '其他', 309, 5.736572297479192, 0, 0.0, 8, 2.19722457733622, 9, '["整体满意度", "性价比", "房间设施"]'::jsonb, '整体满意度', '性价比', '房间设施', '未知酒店', '未知地点', '匿名', '作为广州本地人，我偶尔住酒店换换心情，常住的是MO，这次换了花园酒店，很是惊喜。', '作为广州本地人，我偶尔住酒店换换心情，常住的是MO，这次换了花园酒店，很是惊喜。花园是广州最老牌的五星酒店，改革开放后算是广州地标了，本地人无人不知，那时是外宾住的，当时还没有四季瑰丽MO。十年前，装修前我也住过，体验也不错。这次是装修后，升级了红棉套房，房间大，设计合理，床垫舒适，按这个价格来说，性价比极高了。服务方面，所有服务人员都很热情，有笑容，尤其多了很多印度服务生，那态度更好，笑得也灿烂。基本上，客人的要求有求必应，服务专业周到，我离开酒店遗漏钱包在保险柜，也马上联系，妥善处理，可以体会出来是正宗五星酒店的服务水平。早餐，4个餐厅，吃的也好。总体来说，这是家有品位，有品质，有文化底蕴的五星酒店，值得！', '2024-08-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660d8', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包括久负盛名的四季、丽思卡尔顿、白天鹅等等，这次花园酒店给我的感受是最棒的，酒店建成虽然年代久了，但是各种细节一点也不马虎，房间灯光的设计恰到好处，不亮也不暗；家具布置使用方便舒适；早餐的每个餐桌都有鲜花；每一个喷泉都干净清洁且保持流水状态；恰逢周一，我还碰到了酒店博物馆闭馆日在按惯例清洁水池，以上所有这些细节都看的出酒店的管理和运作非常良好。酒店四楼的博物馆完全超出了我的想象，开始以为会是一个简单的展示，但其实非常专业，很值得一看。餐厅出品也非常棒，在荔湾亭吃了两顿饭，出品很不错，服务人员会主动告诉我怎么点餐最划算；泳池水干净清澈，配备的救生人员也足够数量，各个角度都能覆盖；酒店大堂富丽堂皇又有底蕴；瀑布和花园的亭台楼阁完美的体现着岭南的风貌。给我办理入住的吴经理，看到我定了前后日期相连的两个订单，一个是普通的花园房，一个是粤韵房，主动帮我把前两天的房间也给升级成了粤韵房，避免我要更换房间的麻烦；入住第二天咨询前台人员，准备购买酒店早餐，前台的Ann小姐特别Nice,见我就是一个人带个五岁小朋友，直接免了早餐，更把后面两天要来会合的孩子爸爸早餐也给送了；离开前一天下午到酒店行政酒廊看看风景喝点东西，行政酒廊的每一位小姐姐都非常亲切周到，主动提供各种信息和服务，其中一位Kitty小姐姐贴心热情的邀请我们第二天一早来酒廊用早餐。入住期间提出的所有要求都及时响应，每天都会送上水果和小食，房间打扫及时卫生，遇到的每一位服务人员都热情耐心，感谢酒店所有人美声甜的小姐姐们和友善贴心的帅哥们，以及所有一丝不苟对品质有所坚持的管理者们，为你们的用心送上大大的赞，也希望能够保留这样的底蕴到地久天长。以后来广州不会再更换酒店了，一定是花园酒店！', '["https://dimg04.c-ctrip.com/images/0232s12000f3zjl9u3DDE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000f3zilnn631F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000f3zkz5140C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-13', '粤韵双床套房', '套房', '家庭亲子', 764, 6.639875833826536, 0, 0.0, 6, 1.9459101490553128, 10, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包括久负盛名的四季、丽思卡尔顿、白天鹅等等，这次花园酒店给我的感受是最棒的，酒店建成虽然年代久了，但是各种细节一点也不马虎，房间灯光的设计恰到好处，不亮也不暗；家具布置使用方便舒适；早餐的每个餐桌都有鲜花；每一个喷泉都干净清洁且保持流水状态；恰逢周一，我还碰到了酒店博物馆闭馆日在按惯例清洁水池，以上所有这些细节都看的出酒店的管理和运作非常良好。酒店四楼的博物馆完全超出了我的想象，开始以为会是一个简单的展示，但其实非常专业，很值得一看。餐厅出品也非常棒，在荔湾亭吃了两顿饭，出品很不错，服务人员会主动告诉我怎么点餐最划算；泳池水干净清澈，配备的救生人员也足够数量，各个角度都能覆盖；酒店大堂富丽堂皇又有底蕴；瀑