INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660d9', '原本对这家建造较早的酒店存有刻板印象，所以只作为备选，还订错了入住日期，在酒店前厅部郑经理热情耐心的远程协调下，不仅调整好日期，还获得了小惊喜。入住后，被酒店红红火火的年味、历史与现代的完美融合和小帅小美们暖暖的服务惊到了。2025的广州春节，为我们整个团队的小伙伴带来了开年好运！', '["https://dimg04.c-ctrip.com/images/0234s12000ibffb96112D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2025-02-05', '花园大床房', '大床房', '朋友出游', 141, 4.955827057601261, 0, 0.0, 3, 1.3862943611198906, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '原本对这家建造较早的酒店存有刻板印象，所以只作为备选，还订错了入住日期，在酒店前', '原本对这家建造较早的酒店存有刻板印象，所以只作为备选，还订错了入住日期，在酒店前厅部郑经理热情耐心的远程协调下，不仅调整好日期，还获得了小惊喜。入住后，被酒店红红火火的年味、历史与现代的完美融合和小帅小美们暖暖的服务惊到了。2025的广州春节，为我们整个团队的小伙伴带来了开年好运！', '2025-02-05', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660da', '相比卓美亚，这里完胜。首先这里窗外毫无景色，我相信选择老牌五星酒店不是为了窗外景色来的，一进酒店大堂所有人都会被那幅红楼梦黄金雕刻所吸引，大堂明亮宽敞，前台办理入住有条不紊，有空房直接升级，赞。大堂礼宾服务周到，人多的时候始终有服务员帮客人按电梯，服务质量和人员完胜卓美亚十条街。房间都重新翻新过，古朴典雅、并且是套房你也敢相信，房间隔音还算不错，只是门不怎么隔音，洗漱用品也升级过了，床品也不错。楼下四家米其林餐厅实在是没机会品尝，下一次一定尝试，酒店内有的园林很不错，瀑布很高，很适合吃完饭在酒店里逛一逛。卫生我唯一没给满分的原因就是泳池的水有些浑浊，不如卓美亚的，不过其他几乎都是优点了，尤其很多航司都在这里过夜，看到阿航的姑娘们的确很美。还会再来', '["https://dimg04.c-ctrip.com/images/0230k12000f4u6p3u8101_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t12000f4uf75z1AD8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000f4uhkm7E654_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000f4ugjx341B4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-15', '红棉双床套房', '套房', '家庭亲子', 327, 5.793013608384144, 0, 0.0, 20, 3.044522437723423, 9, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '相比卓美亚，这里完胜。首先这里窗外毫无景色，我相信选择老牌五星酒店不是为了窗外景', '相比卓美亚，这里完胜。首先这里窗外毫无景色，我相信选择老牌五星酒店不是为了窗外景色来的，一进酒店大堂所有人都会被那幅红楼梦黄金雕刻所吸引，大堂明亮宽敞，前台办理入住有条不紊，有空房直接升级，赞。大堂礼宾服务周到，人多的时候始终有服务员帮客人按电梯，服务质量和人员完胜卓美亚十条街。房间都重新翻新过，古朴典雅、并且是套房你也敢相信，房间隔音还算不错，只是门不怎么隔音，洗漱用品也升级过了，床品也不错。楼下四家米其林餐厅实在是没机会品尝，下一次一定尝试，酒店内有的园林很不错，瀑布很高，很适合吃完饭在酒店里逛一逛。卫生我唯一没给满分的原因就是泳池的水有些浑浊，不如卓美亚的，不过其他几乎都是优点了，尤其很多航司都在这里过夜，看到阿航的姑娘们的确很美。还会再来', '2024-08-15', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660db', '??酒店性价比很高，房间也非常干净，服务也很周到，酒店也特别有氛围感，特别有城市花园和小世外桃源的感觉，不愧是花园酒店～下次还会再选择这里的??', '["https://dimg04.c-ctrip.com/images/0230a12000fm11qurA336_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000fm141j609C7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000fm12xs47164_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-17', '花园双床房', '双床房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 10, 2.3978952727983707, 7, '["性价比", "整体满意度", "卫生状况"]'::jsonb, '性价比', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '??酒店性价比很高，房间也非常干净，服务也很周到，酒店也特别有氛围感，特别有城市', '??酒店性价比很高，房间也非常干净，服务也很周到，酒店也特别有氛围感，特别有城市花园和小世外桃源的感觉，不愧是花园酒店～下次还会再选择这里的??', '2024-09-17', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660dc', '一如既往的好，喜欢。床特别舒服。', '["https://dimg04.c-ctrip.com/images/0235612000heo2gvdA039_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000heobb4lAABE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000heo1cko8792_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-25', '花园大床房', '大床房', '商务出差', 16, 2.833213344056216, 0, 0.0, 65, 4.189654742026425, 4, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '一如既往的好，喜欢。床特别舒服。', '一如既往的好，喜欢。床特别舒服。', '2024-12-25', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660df', '来广州出差选择最多的酒店之一，设施设备维护妥当，床品的质量也不错，不足的地方在于健身房的设备老旧，只有部分器械做了更换，另外房间的淋浴房水压有点小。', '["https://dimg04.c-ctrip.com/images/0231c12000fgi9hls2CF7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-09-08', '花园双床房', '双床房', '商务出差', 74, 4.31748811353631, 0, 0.0, 8, 2.19722457733622, 8, '["房间设施", "公共设施"]'::jsonb, '房间设施', '公共设施', NULL, '未知酒店', '未知地点', '匿名', '来广州出差选择最多的酒店之一，设施设备维护妥当，床品的质量也不错，不足的地方在于', '来广州出差选择最多的酒店之一，设施设备维护妥当，床品的质量也不错，不足的地方在于健身房的设备老旧，只有部分器械做了更换，另外房间的淋浴房水压有点小。', '2024-09-08', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660e0', '广州花园酒店入住体验极佳，设施先进，服务细致，卫生干净，环境宁静舒适，每个细节都彰显高品质，让人印象深刻。', '["https://dimg04.c-ctrip.com/images/0231012000gf9kkzq7121_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000gf9a9sj6DB3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235912000gfa70ee60D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-01', '花园双床房', '双床房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 3, 1.3862943611198906, 7, '["整体满意度", "房间设施", "卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '广州花园酒店入住体验极佳，设施先进，服务细致，卫生干净，环境宁静舒适，每个细节都', '广州花园酒店入住体验极佳，设施先进，服务细致，卫生干净，环境宁静舒适，每个细节都彰显高品质，让人印象深刻。', '2024-11-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660e1', '不愧是老牌五星酒店，贴心温暖，细致到让你无法想象：酒店有三个早餐厅，第一天是1楼的瀑布餐厅，享受大自然的美妙，第二天是顶楼的旋转餐厅，伏视高空美景，第三天是三楼的精致早茶。美味惊艳。
     楼层服务员：lili每天换这花样送惊喜', '["https://dimg04.c-ctrip.com/images/0234v12000eyrdteqEBF9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000eyrpa1kA443_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-01', '花园双床房', '双床房', '家庭亲子', 116, 4.762173934797756, 0, 0.0, 15, 2.772588722239781, 9, '["餐饮设施", "客房服务", "整体满意度"]'::jsonb, '餐饮设施', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '不愧是老牌五星酒店，贴心温暖，细致到让你无法想象：酒店有三个早餐厅，第一天是1楼', '不愧是老牌五星酒店，贴心温暖，细致到让你无法想象：酒店有三个早餐厅，第一天是1楼的瀑布餐厅，享受大自然的美妙，第二天是顶楼的旋转餐厅，伏视高空美景，第三天是三楼的精致早茶。美味惊艳。
     楼层服务员：lili每天换这花样送惊喜', '2024-08-01', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660e2', '花园酒店名不虚传，大堂金碧辉煌，花园漂亮大气，餐饮美味，服务非常贴心，环境优美。尤其是30楼行政酒廊的Carrie服务非常周到，对小朋友很有耐心，细心，中文说的非常好?还有Aimee 和Echo美丽大方，热情好客，让客人有宾至如归的感觉，下次来广州还住这里！', '["https://dimg04.c-ctrip.com/images/0232q12000f6ih3mc70CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000f6ibrszC5D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000f6ihx0c953B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000f6iht3vB3F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000f6i2x9z2F2E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000f6ict8k6C0A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000f6icbrxEABA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000f6iekma69CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000f6i516q18D1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-19', '花园大床房', '大床房', '家庭亲子', 129, 4.867534450455582, 0, 0.0, 3, 1.3862943611198906, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店名不虚传，大堂金碧辉煌，花园漂亮大气，餐饮美味，服务非常贴心，环境优美。', '花园酒店名不虚传，大堂金碧辉煌，花园漂亮大气，餐饮美味，服务非常贴心，环境优美。尤其是30楼行政酒廊的Carrie服务非常周到，对小朋友很有耐心，细心，中文说的非常好?还有Aimee 和Echo美丽大方，热情好客，让客人有宾至如归的感觉，下次来广州还住这里！', '2024-08-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660e3', '谢谢，这次会议连着住1周，加上在花园第N次入住，前台Betty给升级。非常好', '["https://dimg04.c-ctrip.com/images/0230512000hlnuarn2E51_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-05', '花园大床房', '大床房', '商务出差', 38, 3.6635616461296463, 0, 0.0, 96, 4.574710978503383, 5, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '谢谢，这次会议连着住1周，加上在花园第N次入住，前台Betty给升级。非常好', '谢谢，这次会议连着住1周，加上在花园第N次入住，前台Betty给升级。非常好', '2025-01-05', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660e4', '选择花园酒店，是一种情怀。
20年前，年幼的我第一次来到广州，就在花园酒店，其间的纸醉金迷震撼到我20年不忘。
20年后，我4岁的女儿第一次来广州，也想让她与我拥有同样的记忆。
特别感谢前台的viria小姐姐，大气的为我们升级了房型，红棉房的瀑布景观让这份美好的记忆再上一层楼，我本来只订了一晚，果断原房续住又加了两晚。
这些年国内国外住过很多酒店，但花园酒店会一直在我的推荐清单上。', '["https://dimg04.c-ctrip.com/images/0233z12000exo29618647_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000exnuusg2E55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000exobas7D5A1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-29', '花园大床房', '大床房', '家庭亲子', 192, 5.262690188904886, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "景观/朝向", "整体满意度"]'::jsonb, '前台服务', '景观/朝向', '整体满意度', '未知酒店', '未知地点', '匿名', '选择花园酒店，是一种情怀。', '选择花园酒店，是一种情怀。
20年前，年幼的我第一次来到广州，就在花园酒店，其间的纸醉金迷震撼到我20年不忘。
20年后，我4岁的女儿第一次来广州，也想让她与我拥有同样的记忆。
特别感谢前台的viria小姐姐，大气的为我们升级了房型，红棉房的瀑布景观让这份美好的记忆再上一层楼，我本来只订了一晚，果断原房续住又加了两晚。
这些年国内国外住过很多酒店，但花园酒店会一直在我的推荐清单上。', '2024-07-29', 5, '前台服务');
