INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660f9', '看了各个平台的评论加上有岭南金的会员卡才来订的酒店，但入住感觉很一般。入住时报了金卡会员号，前台没有任何关于金卡会员的介绍。客房没升级、免费早餐也不提、酒廊礼遇还是在我特意询问后才给了一张一个人的礼遇卡。什么欢迎水果，入住三天毛都没看见。我也是开了眼了！
但是酒店装潢很漂亮，公共设施维护很好。只是客房卫生间反味，房型过于紧凑。给娃买了毛绒纪念品，小姐姐得知我们不用开发票直接给我个人微信二维码让我缴费……呵呵了…', '["https://dimg04.c-ctrip.com/images/0230i12000etzfo8nD94A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000etzz3gl451D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000etzwb062F56_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000etzviutC344_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-07-19', '花园双床房', '双床房', '家庭亲子', 207, 5.337538079701318, 0, 0.0, 2, 1.0986122886681098, 8, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '看了各个平台的评论加上有岭南金的会员卡才来订的酒店，但入住感觉很一般。入住时报了', '看了各个平台的评论加上有岭南金的会员卡才来订的酒店，但入住感觉很一般。入住时报了金卡会员号，前台没有任何关于金卡会员的介绍。客房没升级、免费早餐也不提、酒廊礼遇还是在我特意询问后才给了一张一个人的礼遇卡。什么欢迎水果，入住三天毛都没看见。我也是开了眼了！
但是酒店装潢很漂亮，公共设施维护很好。只是客房卫生间反味，房型过于紧凑。给娃买了毛绒纪念品，小姐姐得知我们不用开发票直接给我个人微信二维码让我缴费……呵呵了…', '2024-07-19', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417660fa', '设施：虽然是85年的酒店但是保养的还真不错。走廊都没什么异味，只是房间小了点，地板有几块咯吱哇吱响。
卫生：打扫的蛮干净的，就是在抽屉拉手上有灰尘。
环境：周围很多大大小小的餐厅，酒店里也有四家米其林，早餐也很丰盛。
服务：入住办理迅速，每层楼都有服务生迎接，早餐餐厅、行政酒廊及桃园的服务都蛮好的。
尊享行政礼遇（含下午茶及欢乐时光-用餐地点锦鲤酒吧行政酒廊）:餐品丰富、服务热情、景观也很棒。
