INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766107', '首先要感谢一下前台的Rebecca,帮我做了房间升级，每次来广州都会选择花园酒店，虽然酒店是最早一批的五星级酒店，但酒店后期有从新翻修过，整体房间设备都很好，酒店的服务也很好，也要感谢一下行政酒廊Carrie,跟她的伙伴们Deepa和Kanchan，她们整体服务真的很好，让你感觉分宾至如归的感觉，真心推荐给大家！！！', '["https://dimg04.c-ctrip.com/images/0233s224x8vbvo8npE745_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d224x8vbu8e1r42D4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f224x8vburw49BAB6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-17', '花园大床房', '大床房', '商务出差', 159, 5.075173815233827, 0, 0.0, 30, 3.4339872044851463, 8, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '首先要感谢一下前台的Rebecca,帮我做了房间升级，每次来广州都会选择花园酒店', '首先要感谢一下前台的Rebecca,帮我做了房间升级，每次来广州都会选择花园酒店，虽然酒店是最早一批的五星级酒店，但酒店后期有从新翻修过，整体房间设备都很好，酒店的服务也很好，也要感谢一下行政酒廊Carrie,跟她的伙伴们Deepa和Kanchan，她们整体服务真的很好，让你感觉分宾至如归的感觉，真心推荐给大家！！！', '2024-06-17', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766108', '广州花园酒店的地理位置十分优越，紧邻市中心，交通便利，无论是商务出差还是休闲旅游，都能轻松抵达城市的各个角落。
步入酒店大堂，大堂的就是一整块刘姥姥进大观园，设计融合了传统与现代元素，展现出独特的艺术气息。前台工作人员的亲切问候和专业服务，让我从一开始就感受到了宾至如归的温暖。
房间内部的装饰同样令人印象深刻。家具布置考究，床品柔软舒适，保证了我每晚都能拥有高质量的睡眠。房间内的现代化设施一应俱全，高速的无线网络都极大地方便了我的工作和生活需求。
服务方面，广州花园酒店的每一位员工都展现出了高度的专业素养和热情周到。他们对客人的需求反应迅速，总是能够提供及时的帮助和解决方案，让我的住宿体验更加顺畅和愉快。特别是前台的Tony，处处能为客人考虑，很贴心。
总体来说，广州花园酒店以其优越的地理位置、典雅的装修风格、舒适的住宿环境、一流的餐饮服务以及专业的员工团队，为我提供了一次卓越的住宿体验。无论是商务出行还是休闲度假，我都会毫不犹豫地向朋友和家人推荐这家酒店，并期待在未来有机会再次入住。', '["https://dimg04.c-ctrip.com/images/0230p12000f2iidikE647_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000f2innvyFAE2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000f2if60s30A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000f2imi8r4499_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000f2i8g3wC61A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000f2icmiq4D81_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231o12000f2if60uED83_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000f2iks497A36_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000f2iogdn19B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-10', '花园双床房', '双床房', '商务出差', 453, 6.118097198041348, 0, 0.0, 11, 2.4849066497880004, 9, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '广州花园酒店的地理位置十分优越，紧邻市中心，交通便利，无论是商务出差还是休闲旅游', '广州花园酒店的地理位置十分优越，紧邻市中心，交通便利，无论是商务出差还是休闲旅游，都能轻松抵达城市的各个角落。
步入酒店大堂，大堂的就是一整块刘姥姥进大观园，设计融合了传统与现代元素，展现出独特的艺术气息。前台工作人员的亲切问候和专业服务，让我从一开始就感受到了宾至如归的温暖。
房间内部的装饰同样令人印象深刻。家具布置考究，床品柔软舒适，保证了我每晚都能拥有高质量的睡眠。房间内的现代化设施一应俱全，高速的无线网络都极大地方便了我的工作和生活需求。
服务方面，广州花园酒店的每一位员工都展现出了高度的专业素养和热情周到。他们对客人的需求反应迅速，总是能够提供及时的帮助和解决方案，让我的住宿体验更加顺畅和愉快。特别是前台的Tony，处处能为客人考虑，很贴心。
总体来说，广州花园酒店以其优越的地理位置、典雅的装修风格、舒适的住宿环境、一流的餐饮服务以及专业的员工团队，为我提供了一次卓越的住宿体验。无论是商务出行还是休闲度假，我都会毫不犹豫地向朋友和家人推荐这家酒店，并期待在未来有机会再次入住。', '2024-08-10', 5, '交通便利性');
