INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176611c', '第一次住花园酒店，据说白金5星的酒店，服务是真的好得无可挑剔！不知道是不是广交会的原因，几乎都是外国人，酒店工作人员的英文水平很高！就车行李生的英文都很流利！
大堂电梯口一直有服务员，每个楼层都全天有服务员，早上还在每层电梯口提供热茶！真的超级棒！
本来订了两晚的房间，说好是不能取消的，但由于特殊原因，跟携程申请，再与酒店沟通，最后同意提前退房，很人性化！
酒店还设有博物馆，很惊艳！果然是广州的名片，以后去广州，只住花园酒店！
