INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766125', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包括久负盛名的四季、丽思卡尔顿、白天鹅等等，这次花园酒店给我的感受是最棒的，酒店建成虽然年代久了，但是各种细节一点也不马虎，房间灯光的设计恰到好处，家具布置的使用舒适度，看的出来设计的用心。酒店四楼的博物馆非常有底蕴，完全超出了我的想象，开始以为会是一个简单的展示，但其实非常专业，很值得一看。酒店的餐厅出品也非常棒，在荔湾亭吃了两顿饭，味道非常不错，服务人员也极热情。泳池水干净清澈，配备的救生人员也足够数量，各个角度都能覆盖。酒店大堂富丽堂皇又有底蕴，瀑布和花园的亭台楼阁完美的体现着岭南的风貌。给我办理入住的吴经理，看到我定了前后日期相连的两个订单，一个是普通的花园房，一个是粤韵房，主动帮我把前两天的房间也给升级成了粤韵房，避免我要更换房间的麻烦；入住第二天咨询前台人员，准备购买酒店早餐，前台的Ann小姐特别Nice，见我就是一个人带个五岁小朋友，直接免了早餐，更把后面两天要来会合的孩子爸爸早餐也给送了；离开前一天下午到酒店行政酒廊看看风景，喝点东西，行政酒廊的每一位小姐姐都非常亲切周到，主动提供各种信息和服务，其中一位Kitty小姐姐热情的邀请我们第二天一早也来酒廊用早餐，欣赏顶楼的风景。入住期间提出的所有要求都及时响应，每天都会贴心的送上水果和小食，房间打扫及时卫生，遇到的每一位服务人员都热情耐心，感谢酒店所有人美声甜的小姐姐们和友善贴心的帅哥们，以及所有为酒店的完善和标准服务一丝不苟的管理者们，为你们的用心和品质送上大大的赞，也希望能够保留这样的底蕴到地久天长。以后来广州不会再更换酒店了，一定是花园酒店！', '["https://dimg04.c-ctrip.com/images/0237012000f3h82k12490_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000f3h67ojF893_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000f3h79xvD62B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-12', '花园大床房', '大床房', '家庭亲子', 705, 6.559615237493242, 0, 0.0, 6, 1.9459101490553128, 10, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包括久负盛名的四季、丽思卡尔顿、白天鹅等等，这次花园酒店给我的感受是最棒的，酒店建成虽然年代久了，但是各种细节一点也不马虎，房间灯光的设计恰到好处，家具布置的使用舒适度，看的出来设计的用心。酒店四楼的博物馆非常有底蕴，完全超出了我的想象，开始以为会是一个简单的展示，但其实非常专业，很值得一看。酒店的餐厅出品也非常棒，在荔湾亭吃了两顿饭，味道非常不错，服务人员也极热情。泳池水干净清澈，配备的救生人员也足够数量，各个角度都能覆盖。酒店大堂富丽堂皇又有底蕴，瀑布和花园的亭台楼阁完美的体现着岭南的风貌。给我办理入住的吴经理，看到我定了前后日期相连的两个订单，一个是普通的花园房，一个是粤韵房，主动帮我把前两天的房间也给升级成了粤韵房，避免我要更换房间的麻烦；入住第二天咨询前台人员，准备购买酒店早餐，前台的Ann小姐特别Nice，见我就是一个人带个五岁小朋友，直接免了早餐，更把后面两天要来会合的孩子爸爸早餐也给送了；离开前一天下午到酒店行政酒廊看看风景，喝点东西，行政酒廊的每一位小姐姐都非常亲切周到，主动提供各种信息和服务，其中一位Kitty小姐姐热情的邀请我们第二天一早也来酒廊用早餐，欣赏顶楼的风景。入住期间提出的所有要求都及时响应，每天都会贴心的送上水果和小食，房间打扫及时卫生，遇到的每一位服务人员都热情耐心，感谢酒店所有人美声甜的小姐姐们和友善贴心的帅哥们，以及所有为酒店的完善和标准服务一丝不苟的管理者们，为你们的用心和品质送上大大的赞，也希望能够保留这样的底蕴到地久天长。以后来广州不会再更换酒店了，一定是花园酒店！', '2024-08-12', 5, '整体满意度');
