INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176612d', '特别有味道的酒店，明年就40周年了，小时候去过，依然很有高级感，很多设施没有变，大理石依然锃亮。质量真好。不旧，时间的味道。精致而高级。到处都是花艺，干净房间设施也蛮不错的。面积也不小。比起现代那些酒店。不一样的气质。性价比也很高。经典就是经典。伟大的设计师贝聿铭作品。小时候也不懂', '["https://dimg04.c-ctrip.com/images/0230d12000diy7yn90218_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000diy8d5g8457_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000diy7qbp645A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000diy820hBDF1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000diy83l4DC82_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000diy7tynE23C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-28', '花园大床房', '大床房', '商务出差', 141, 4.955827057601261, 1, 0.6931471805599453, 23, 3.1780538303479458, 8, '["整体满意度", "房间设施", "性价比"]'::jsonb, '整体满意度', '房间设施', '性价比', '未知酒店', '未知地点', '匿名', '特别有味道的酒店，明年就40周年了，小时候去过，依然很有高级感，很多设施没有变，', '特别有味道的酒店，明年就40周年了，小时候去过，依然很有高级感，很多设施没有变，大理石依然锃亮。质量真好。不旧，时间的味道。精致而高级。到处都是花艺，干净房间设施也蛮不错的。面积也不小。比起现代那些酒店。不一样的气质。性价比也很高。经典就是经典。伟大的设计师贝聿铭作品。小时候也不懂', '2024-03-28', 5, '整体满意度');
