虽然前台接待因为繁忙出了一点小差错，但是我离店后，跟踪服务的客服经理非常耐心细致入微的解决了售后服务问题，非常满意！！！', '2024-03-07', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176612f', '每位酒店的工作人员都非常的热情，让人感觉很舒服，环境也很赞，最主要的是干净卫生，这个价格入住这个酒店真的是超值，下次有机会一定会再来，停车方便，入住很快，房间也比较舒适，价格不贵，环境也不错，房间干净，入住首选，满意！特别感谢LiVen服务不错??', '["https://dimg04.c-ctrip.com/images/0233g12000jrk7zu39895_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000jrkn3l11642_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000jrlbozjD35F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-13', '花园双床房', '双床房', '家庭亲子', 124, 4.8283137373023015, 0, 0.0, 2, 1.0986122886681098, 6, '["整体满意度", "卫生状况", "性价比"]'::jsonb, '整体满意度', '卫生状况', '性价比', '未知酒店', '未知地点', '匿名', '每位酒店的工作人员都非常的热情，让人感觉很舒服，环境也很赞，最主要的是干净卫生，', '每位酒店的工作人员都非常的热情，让人感觉很舒服，环境也很赞，最主要的是干净卫生，这个价格入住这个酒店真的是超值，下次有机会一定会再来，停车方便，入住很快，房间也比较舒适，价格不贵，环境也不错，房间干净，入住首选，满意！特别感谢LiVen服务不错??', '2025-04-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766130', '房间卫生整洁、服务态度好', '["https://dimg04.c-ctrip.com/images/0235m12000f0uifgpE846_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000f0ui87o7B98_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000f0ub0xr5D5B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000f0ubsxyBC0E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-06', '花园双床房', '双床房', '朋友出游', 12, 2.5649493574615367, 0, 0.0, 13, 2.6390573296152584, 4, '["卫生状况", "前台服务"]'::jsonb, '卫生状况', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '房间卫生整洁、服务态度好', '房间卫生整洁、服务态度好', '2024-08-06', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766131', '非常满意的一次度假体验，体验超出预期。特别要表扬前台的cecilia小姐姐，悉心安排好我们的住宿，不厌其烦，入住后我们有一间房需要更换为双床，又要加床，她都帮我们解决，我们也按照酒店规矩付了需要增加的费用，但整个过程令我们感到满意。我们和朋友两家人就在广州市附近居住，我们安排入住当天上午到南越王墓参观，然后入住花园酒店，下午闲逛酒店，还参观了花园酒店博物馆，晚上就在酒店内吃饭+蒲吧，开心快乐地在酒店欢度美好时光！！第二天我们还去了楼顶的旋转餐厅吃早餐，心满意足地离开这里！！我们决定以后再来一次花园酒店，要多住一两天！！', '["https://dimg04.c-ctrip.com/images/0233r12000ii7ybeq5255_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000ii7rs382892_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000ii8dde04F81_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000ii7nezv27ED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000ii89qqqD280_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000ii84hdy65B1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000ii7tbs2CD46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000ii7gpap1207_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000ii88c2i7E0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-13', '红棉大床套房', '套房', '情侣出游', 262, 5.572154032177765, 0, 0.0, 20, 3.044522437723423, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '非常满意的一次度假体验，体验超出预期。特别要表扬前台的cecilia小姐姐，悉心', '非常满意的一次度假体验，体验超出预期。特别要表扬前台的cecilia小姐姐，悉心安排好我们的住宿，不厌其烦，入住后我们有一间房需要更换为双床，又要加床，她都帮我们解决，我们也按照酒店规矩付了需要增加的费用，但整个过程令我们感到满意。我们和朋友两家人就在广州市附近居住，我们安排入住当天上午到南越王墓参观，然后入住花园酒店，下午闲逛酒店，还参观了花园酒店博物馆，晚上就在酒店内吃饭+蒲吧，开心快乐地在酒店欢度美好时光！！第二天我们还去了楼顶的旋转餐厅吃早餐，心满意足地离开这里！！我们决定以后再来一次花园酒店，要多住一两天！！', '2025-02-13', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766132', '中国仅有的白金五星酒店之一，服务到位，房间布局优雅，干湿分离，客厅坐着聊天喝咖啡对着窗外美景简直舒服享受，后花园是岭南园林风格，面积很大，大瀑布是标志景观。', '["https://dimg04.c-ctrip.com/images/0234n12000dj6qvpl6038_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000dj6rbra4830_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000dj6riwhF03F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000dj6s71o8698_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000dj6r8736442_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000dj6rf634E3D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-29', '花园大床房', '大床房', '情侣出游', 78, 4.3694478524670215, 0, 0.0, 125, 4.836281906951478, 9, '["房间设施", "整体满意度", "景观/朝向"]'::jsonb, '房间设施', '整体满意度', '景观/朝向', '未知酒店', '未知地点', '匿名', '中国仅有的白金五星酒店之一，服务到位，房间布局优雅，干湿分离，客厅坐着聊天喝咖啡', '中国仅有的白金五星酒店之一，服务到位，房间布局优雅，干湿分离，客厅坐着聊天喝咖啡对着窗外美景简直舒服享受，后花园是岭南园林风格，面积很大，大瀑布是标志景观。', '2024-03-29', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766133', '不愧是国内白金五星，据查还是国资企业管理，硬件和软件方面，还有用心程度，很多已经超过国际五星甚至超五星了，在接待外宾的专业程度上，更是能虐其他酒店几条街，真心为民族品牌而自豪。', '["https://dimg04.c-ctrip.com/images/0235h12000ddm324e25FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000ddm2ogk562B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000ddm3gcv3E91_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-09', '红棉大床套房', '套房', '商务出差', 88, 4.48863636973214, 0, 0.0, 7, 2.079441541679836, 8, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '不愧是国内白金五星，据查还是国资企业管理，硬件和软件方面，还有用心程度，很多已经', '不愧是国内白金五星，据查还是国资企业管理，硬件和软件方面，还有用心程度，很多已经超过国际五星甚至超五星了，在接待外宾的专业程度上，更是能虐其他酒店几条街，真心为民族品牌而自豪。', '2024-03-09', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766134', '全国3家白金五星级酒店之一的广州花园酒店，向往已久，虽开业有近40年，仍豪华气派。前台办理入住很快，还赠送了鲜花和水果，很是温暖。酒店后花园瀑布游鱼，花草树木，小径通幽，闹中取静，在此散步心情愉悦。房间还比较宽敞，灯光明亮，被褥舒适柔软，淋浴水大。房内Naspresso胶囊咖啡机一粒开压香飘全屋，旅途疲劳顿时全消。', '["https://dimg04.c-ctrip.com/images/0234x12000d8met2x44F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000d8meou12C82_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000d8mdlby8012_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000d8md3khBC0A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000d8mdrivBB14_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000d8mepceD996_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-18', '花园双床房', '双床房', '朋友出游', 158, 5.068904202220232, 0, 0.0, 103, 4.6443908991413725, 9, '["房间设施", "整体满意度", "前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '全国3家白金五星级酒店之一的广州花园酒店，向往已久，虽开业有近40年，仍豪华气派', '全国3家白金五星级酒店之一的广州花园酒店，向往已久，虽开业有近40年，仍豪华气派。前台办理入住很快，还赠送了鲜花和水果，很是温暖。酒店后花园瀑布游鱼，花草树木，小径通幽，闹中取静，在此散步心情愉悦。房间还比较宽敞，灯光明亮，被褥舒适柔软，淋浴水大。房内Naspresso胶囊咖啡机一粒开压香飘全屋，旅途疲劳顿时全消。', '2024-02-18', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766135', '五星标房价格合理，性价比挺高。不过，入住时分配的房间位置不太理想，在楼道尽头，紧挨着工作人员通道，来来往往关门声特别大，休息时会受到些干扰，这点希望酒店后续能优化房间安排 。把劣质房间闲置没必要精明算计影响顾客入住体验。
但不得不夸夸LiVen小姐姐，从踏入酒店的那一刻起，她就热情相迎，还耐心细致地介绍酒店各项设施。后来我向她询问周边景点，她不仅给出详细的游玩攻略，还热心帮忙预约车辆，服务特别周到。因为她的专业和热情，这次入住的很多小瑕疵都被完美化解，下次来这边还选这家。', '["https://dimg04.c-ctrip.com/images/0232112000jox664e703F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000jowwas1F359_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000joxps9l2319_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-10', '花园大床房', '大床房', '独自旅行', 239, 5.480638923341991, 0, 0.0, 23, 3.1780538303479458, 8, '["前台服务", "安静程度", "性价比"]'::jsonb, '前台服务', '安静程度', '性价比', '未知酒店', '未知地点', '匿名', '五星标房价格合理，性价比挺高。不过，入住时分配的房间位置不太理想，在楼道尽头，紧', '五星标房价格合理，性价比挺高。不过，入住时分配的房间位置不太理想，在楼道尽头，紧挨着工作人员通道，来来往往关门声特别大，休息时会受到些干扰，这点希望酒店后续能优化房间安排 。把劣质房间闲置没必要精明算计影响顾客入住体验。
但不得不夸夸LiVen小姐姐，从踏入酒店的那一刻起，她就热情相迎，还耐心细致地介绍酒店各项设施。后来我向她询问周边景点，她不仅给出详细的游玩攻略，还热心帮忙预约车辆，服务特别周到。因为她的专业和热情，这次入住的很多小瑕疵都被完美化解，下次来这边还选这家。', '2025-04-10', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766137', '过年期间带娃来入住，酒店虽然老但布置的很有年味，羊羊家庭房是套房，宽敞，应该是新装修的房间，第一天晚餐是酒店自助晚餐，瀑布餐厅很别致，晚餐也很丰盛，当天是情人节每桌还特别送了龙虾牛排和情人节蛋糕，非常贴心，味道很好，性价比非常高，给我留下了很好的印象。就是过年期间入住慢但可以理解，希望这方面还有待提升！酒店楼下就是地铁站，地理位置绝佳！', '["https://dimg04.c-ctrip.com/images/0231w12000dvvxmerD961_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000dvvz8yo6289_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000dvw0ek03E2F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000dvvtnpe2909_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000dvw11ed9E04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000dvvtdl13D5B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000dvvrt2hFB66_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000dvvqu2825F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235012000dvvx7uzB6D5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-05', '羊羊得意主题大床房', '主题房', '家庭亲子', 169, 5.135798437050262, 0, 0.0, 13, 2.6390573296152584, 8, '["性价比", "餐饮设施", "退房/入住效率"]'::jsonb, '性价比', '餐饮设施', '退房/入住效率', '未知酒店', '未知地点', '匿名', '过年期间带娃来入住，酒店虽然老但布置的很有年味，羊羊家庭房是套房，宽敞，应该是新', '过年期间带娃来入住，酒店虽然老但布置的很有年味，羊羊家庭房是套房，宽敞，应该是新装修的房间，第一天晚餐是酒店自助晚餐，瀑布餐厅很别致，晚餐也很丰盛，当天是情人节每桌还特别送了龙虾牛排和情人节蛋糕，非常贴心，味道很好，性价比非常高，给我留下了很好的印象。就是过年期间入住慢但可以理解，希望这方面还有待提升！酒店楼下就是地铁站，地理位置绝佳！', '2024-05-05', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766138', '亲子家庭出行，花园酒店的春节氛围浓郁，捏小泥人非常受孩子喜欢，还带回家啦～
