但是服务还是很受影响，连住两晚，备品没有续上，房间没有主动打扫，没有开夜床服务，浴盐第一天用了，第二天居然没有补上。宝宝备品没有，床围没有，总之有点一言难尽', '2024-02-16', 3, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176613a', '房间干净、整洁、卫生、舒适、宽敞。设施又齐全，咖啡机、茶包等产品齐全！19楼服务生小朱态度非常好??还有一楼服务生也是，这次帮忙拿行李，后来发现水杯拍照时忘了又给我跑了一趟。', '["https://dimg04.c-ctrip.com/images/0234i12000dcoglho6134_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000dcof8c16D07_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000dco8jlmF73F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-05', '花园大床房', '大床房', '独自旅行', 87, 4.477336814478207, 0, 0.0, 21, 3.091042453358316, 8, '["卫生状况", "房间设施", "前台服务"]'::jsonb, '卫生状况', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '房间干净、整洁、卫生、舒适、宽敞。设施又齐全，咖啡机、茶包等产品齐全！19楼服务', '房间干净、整洁、卫生、舒适、宽敞。设施又齐全，咖啡机、茶包等产品齐全！19楼服务生小朱态度非常好??还有一楼服务生也是，这次帮忙拿行李，后来发现水杯拍照时忘了又给我跑了一趟。', '2024-03-05', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176613b', '订的红棉房套餐很值，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵吧，给的几间都是粤韵；房间很大，设施新，卫生、服务、环境都很好，早餐在瀑布餐厅也不错，4楼还有个博物馆，入住外国人多。餐饮券能在酒吧用。总体套餐超值。', '["https://dimg04.c-ctrip.com/images/0235k12000d2ds9geB2FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000d2dmshy6CA1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000d2dmh0i25CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000d2e19nn32BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000d2drpc7263A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000d2e0suq96F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000d2dz9o12017_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000d2dqc7m7597_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000d2dqhhf481C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-28', '红棉双床套房', '套房', '家庭亲子', 115, 4.7535901911063645, 0, 0.0, 36, 3.610917912644224, 9, '["性价比", "餐饮设施", "房间设施"]'::jsonb, '性价比', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '订的红棉房套餐很值，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵', '订的红棉房套餐很值，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵吧，给的几间都是粤韵；房间很大，设施新，卫生、服务、环境都很好，早餐在瀑布餐厅也不错，4楼还有个博物馆，入住外国人多。餐饮券能在酒吧用。总体套餐超值。', '2024-01-28', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176613c', '节前选酒店时曾犹豫过，最后还是订了花园，入住之后发现自己作出了最英明的决策～整个花园酒店，都沉浸在浓浓的的广府农历新年的喜悦气氛之中，大年初一还近距离、完整观赏了南国舞龙舞狮表演，太太太赞了??
至于房间设施，发现没有咖啡，问服务员要了咖啡机＆咖啡，也解决了??
2022年的春节我也住花园，那次房间里会摆上一支玫瑰、几个油角笑口枣什么的，今年就没有摆了', '["https://dimg04.c-ctrip.com/images/0206p12000d6q9re36383_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0202912000d6q9zbd3850_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0234n12000d6pvmzz325F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000d6pqlc2587B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000d6pu5hfA81B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000d6q1yywAE31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000d6q6uriC829_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000d6q65zuC080_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000d6pzww8D87B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000d6pupnuE1DF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000d6pv1en5338_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-12', '花园大床房', '大床房', '独自旅行', 177, 5.181783550292085, 0, 0.0, 9, 2.302585092994046, 8, '["整体满意度", "客房服务", "房间设施"]'::jsonb, '整体满意度', '客房服务', '房间设施', '未知酒店', '未知地点', '匿名', '节前选酒店时曾犹豫过，最后还是订了花园，入住之后发现自己作出了最英明的决策～整个', '节前选酒店时曾犹豫过，最后还是订了花园，入住之后发现自己作出了最英明的决策～整个花园酒店，都沉浸在浓浓的的广府农历新年的喜悦气氛之中，大年初一还近距离、完整观赏了南国舞龙舞狮表演，太太太赞了??
