INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766140', '服务热情，宾至如归，老人小孩有问题第一时间来帮忙解决，服务态度特别好。
房间舒适，干净整洁，地理位置优越，门口就有地铁站，去吃饭玩都很方便。真心喜欢这里的后花园，曲径通幽，鸟语花香，闹中取静，静谧美好，还有博物馆，了解了很多酒店的历史。', '["https://dimg04.c-ctrip.com/images/0236212000d7kziua0DF6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000d7koxvhBA49_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000d7l3osfED55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000d7kq3ue8DB5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234x12000d7ko9w52DA1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000d7l392fE91E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000d7ksfeu2318_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231i12000d7ojkns33BC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-15', '红棉大床套房', '套房', '家庭亲子', 118, 4.77912349311153, 0, 0.0, 5, 1.791759469228055, 8, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '服务热情，宾至如归，老人小孩有问题第一时间来帮忙解决，服务态度特别好。', '服务热情，宾至如归，老人小孩有问题第一时间来帮忙解决，服务态度特别好。
房间舒适，干净整洁，地理位置优越，门口就有地铁站，去吃饭玩都很方便。真心喜欢这里的后花园，曲径通幽，鸟语花香，闹中取静，静谧美好，还有博物馆，了解了很多酒店的历史。', '2024-02-15', 5, '前台服务');
