INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766143', '服务好 环境好', '["https://dimg04.c-ctrip.com/images/0236212000ey7bk1nFDBF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-31', '花园双床房', '双床房', '商务出差', 7, 2.079441541679836, 0, 0.0, 54, 4.007333185232471, 2, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '服务好 环境好', '服务好 环境好', '2024-07-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766144', '房间很奇葩，开放式卫生间，可以想象*******便秘的场景，而且住到第三天被褥就会开始返潮……沟通了下前台，这种奇葩装修是老板喜欢，果然品味清奇。早餐八点左右必然排队，餐品挺难吃，我一便宜嘴巴说难吃就真真的千真万确了??，我觉得这种难吃是不以人的意志而转移的??。行政酒廊没烈酒和调酒，比较少见，全冷餐，在空调不行的情况下对老人和妇幼有点不和谐，基本上脱不了外套。酒店所有服务人员的素质很高，非常热情，仅次于海景花园了。', '["https://dimg04.c-ctrip.com/images/0235a12000d250b5jE4E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j12000d2qg3xh37B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000d2qmtmaF59A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2024-01-29', '花园双床房', '双床房', '情侣出游', 210, 5.351858133476067, 0, 0.0, 12, 2.5649493574615367, 9, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间很奇葩，开放式卫生间，可以想象*******便秘的场景，而且住到第三天被褥就', '房间很奇葩，开放式卫生间，可以想象*******便秘的场景，而且住到第三天被褥就会开始返潮……沟通了下前台，这种奇葩装修是老板喜欢，果然品味清奇。早餐八点左右必然排队，餐品挺难吃，我一便宜嘴巴说难吃就真真的千真万确了??，我觉得这种难吃是不以人的意志而转移的??。行政酒廊没烈酒和调酒，比较少见，全冷餐，在空调不行的情况下对老人和妇幼有点不和谐，基本上脱不了外套。酒店所有服务人员的素质很高，非常热情，仅次于海景花园了。', '2024-01-29', 3, '房间设施');
