INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766162', '一走进大厅，高端大气上档次，酒店还有一个博物馆，可以去逛逛，出行很方便，酒店出来就是地铁淘金站，总体感觉很不错', '["https://dimg04.c-ctrip.com/images/0230c12000d5qvdg4C77B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000d5qid7f9669_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000d5quj3i164B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-08', '花园双床房', '双床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 29, 3.4011973816621555, 7, '["交通便利性", "整体满意度", "公共设施"]'::jsonb, '交通便利性', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '一走进大厅，高端大气上档次，酒店还有一个博物馆，可以去逛逛，出行很方便，酒店出来', '一走进大厅，高端大气上档次，酒店还有一个博物馆，可以去逛逛，出行很方便，酒店出来就是地铁淘金站，总体感觉很不错', '2024-02-08', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766163', '真正的民旅品牌，超白金酒店。因为是在广交会期间，人山人海，但配备的服务员多，秩序井然。礼宾部的讲解人员小陈热情主动，认真讲解酒店的前世今生。由于外国人太多，酒店的香薰味太浓，引起嗓子不舒服，让前台经理把房间窗户打开通风，这才合适了。也巧，30楼的行政酒廊在这期间开放了，这两天躲在楼上看风景，喝下午茶，真是太好了。', '["https://dimg04.c-ctrip.com/images/0236m12000chhvslh4D2E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000chhwyhs019A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000chhwm6b002A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000chhsf4bA25E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000chhr0ly8C3F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000chhyb8m1A67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000chi2ccyCC78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000chhu2ik4AFF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000chhw3r3C98F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-31', '花园大床房', '大床房', '情侣出游', 157, 5.062595033026967, 0, 0.0, 114, 4.74493212836325, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '真正的民旅品牌，超白金酒店。因为是在广交会期间，人山人海，但配备的服务员多，秩序', '真正的民旅品牌，超白金酒店。因为是在广交会期间，人山人海，但配备的服务员多，秩序井然。礼宾部的讲解人员小陈热情主动，认真讲解酒店的前世今生。由于外国人太多，酒店的香薰味太浓，引起嗓子不舒服，让前台经理把房间窗户打开通风，这才合适了。也巧，30楼的行政酒廊在这期间开放了，这两天躲在楼上看风景，喝下午茶，真是太好了。', '2023-10-31', 5, '前台服务');
