INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766167', '绝对大气的酒店！淘金地铁站出来步行三分钟就到，出行极方便。附近有广州酒家和点都德，还有糖水店，餐饮极方便。', '["https://dimg04.c-ctrip.com/images/0231s12000d3odfmwDCF0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000d3oclcl2059_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-01', '花园双床房', '双床房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 17, 2.8903717578961645, 8, '["交通便利性", "周边配套"]'::jsonb, '交通便利性', '周边配套', NULL, '未知酒店', '未知地点', '匿名', '绝对大气的酒店！淘金地铁站出来步行三分钟就到，出行极方便。附近有广州酒家和点都德', '绝对大气的酒店！淘金地铁站出来步行三分钟就到，出行极方便。附近有广州酒家和点都德，还有糖水店，餐饮极方便。', '2024-02-01', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766169', '房间挺好的，酒店也很漂亮。但那天晚上半夜有人门口打电话吵到我睡觉了很不高兴。后来跟携程反馈了才处理好', '["https://dimg04.c-ctrip.com/images/0236z12000dqz6cpc16FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000dqz5mfmB751_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-22', '花园双床房', '双床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 40, 3.713572066704308, 6, '["安静程度", "前台服务"]'::jsonb, '安静程度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '房间挺好的，酒店也很漂亮。但那天晚上半夜有人门口打电话吵到我睡觉了很不高兴。后来', '房间挺好的，酒店也很漂亮。但那天晚上半夜有人门口打电话吵到我睡觉了很不高兴。后来跟携程反馈了才处理好', '2024-04-22', 5, '安静程度');
