INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176616c', '订之前好担心会设备陈旧，原来是我多虑了，值得下次再来', '["https://dimg04.c-ctrip.com/images/0232v12000dfybzy434A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-18', '红棉大床套房', '套房', '商务出差', 26, 3.295836866004329, 0, 0.0, 4, 1.6094379124341005, 5, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '订之前好担心会设备陈旧，原来是我多虑了，值得下次再来', '订之前好担心会设备陈旧，原来是我多虑了，值得下次再来', '2024-03-18', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176616d', '第一批的白金五星酒店，设施虽然有些旧了，服务很好。如果晚上行政酒廊可以看到外面的夜景，因该更惬意哦。', '["https://dimg04.c-ctrip.com/images/0235312000d25srrq9817_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000d265loxDCC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000d25oe5vC243_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000d25nowf8452_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-27', '花园双床房', '双床房', '朋友出游', 50, 3.9318256327243257, 0, 0.0, 17, 2.8903717578961645, 6, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '第一批的白金五星酒店，设施虽然有些旧了，服务很好。如果晚上行政酒廊可以看到外面的', '第一批的白金五星酒店，设施虽然有些旧了，服务很好。如果晚上行政酒廊可以看到外面的夜景，因该更惬意哦。', '2024-01-27', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176616e', '非常满意的一次入住，酒店方面没有因为客人提出的房间升级而板着面孔加钱的要求？前台小姐姐周到，耐心而且热情，尽量满足客人的需求，其实升级房型看似酒店损失，而实际上，客人的好评及口口相传比广告效益更好，这是格局长远的表现，看看前台办理入住的盛况？说明了酒店领导的眼光！感谢你们，我们还会再见！', '["https://dimg04.c-ctrip.com/images/0232g12000cjtzhhb2056_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000cjttg5d1974_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-10', '花园双床房', '双床房', '朋友出游', 144, 4.976733742420574, 0, 0.0, 22, 3.1354942159291497, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '非常满意的一次入住，酒店方面没有因为客人提出的房间升级而板着面孔加钱的要求？前台', '非常满意的一次入住，酒店方面没有因为客人提出的房间升级而板着面孔加钱的要求？前台小姐姐周到，耐心而且热情，尽量满足客人的需求，其实升级房型看似酒店损失，而实际上，客人的好评及口口相传比广告效益更好，这是格局长远的表现，看看前台办理入住的盛况？说明了酒店领导的眼光！感谢你们，我们还会再见！', '2023-11-10', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176616f', '服务很好，订了三晚，后面两天给我升级了房型，非常感谢！酒店的花园和博物馆也很有看头，女儿很喜欢，天天要去逛花园', '["https://dimg04.c-ctrip.com/images/0232r12000cy0eqbf6DBB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000cy0864a2927_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000cy0bvk6E9A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000cy0c1y41500_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000cy0ddly4353_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-15', '花园大床房', '大床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 10, 2.3978952727983707, 7, '["前台服务", "整体满意度", "公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '服务很好，订了三晚，后面两天给我升级了房型，非常感谢！酒店的花园和博物馆也很有看', '服务很好，订了三晚，后面两天给我升级了房型，非常感谢！酒店的花园和博物馆也很有看头，女儿很喜欢，天天要去逛花园', '2024-01-15', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766170', '房间重新装修过，还不错，就是浴缸摆放位置有点奇怪。初一早上有舞龙醒狮，很有氛围', '["https://dimg04.c-ctrip.com/images/0236512000diz05ky935E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-28', '粤韵大床套房', '套房', '家庭亲子', 39, 3.688879454113936, 0, 0.0, 11, 2.4849066497880004, 6, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '房间重新装修过，还不错，就是浴缸摆放位置有点奇怪。初一早上有舞龙醒狮，很有氛围', '房间重新装修过，还不错，就是浴缸摆放位置有点奇怪。初一早上有舞龙醒狮，很有氛围', '2024-03-28', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766171', '酒店非常好，物有所值，餐厅也很好吃，服务人员态度都很好，入住的时候发小礼物和点心，房间干净，隔音也好，可以说性价比相当高，就是淋浴在浴缸里的，我不太喜欢，要是可以分离就好了。体验了游泳池，还有免费的零食和冰淇淋。酒店总体的设施好得不得了，很多机组入住，国庆期间也有很多人办酒席，花园很漂亮，有博物馆。
自助早餐说实话非常一般，但水平比一般的酒店要好，主要还是外面的早茶太好吃了，一下子就把很普通的酒店自助餐比下去了。有30f旋转餐厅和大厅的瀑布餐厅可以选，旋转餐厅有点头晕，还挺热，建议还是瀑布餐厅吧。', '["https://dimg04.c-ctrip.com/images/0233t12000ciyh0lq968D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i12000ciygr14A011_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234h12000ciy85pgFAFB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-06', '红棉双床套房', '套房', '商务出差', 251, 5.529429087511423, 0, 0.0, 4, 1.6094379124341005, 9, '["性价比", "整体满意度", "餐饮设施"]'::jsonb, '性价比', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店非常好，物有所值，餐厅也很好吃，服务人员态度都很好，入住的时候发小礼物和点心', '酒店非常好，物有所值，餐厅也很好吃，服务人员态度都很好，入住的时候发小礼物和点心，房间干净，隔音也好，可以说性价比相当高，就是淋浴在浴缸里的，我不太喜欢，要是可以分离就好了。体验了游泳池，还有免费的零食和冰淇淋。酒店总体的设施好得不得了，很多机组入住，国庆期间也有很多人办酒席，花园很漂亮，有博物馆。
自助早餐说实话非常一般，但水平比一般的酒店要好，主要还是外面的早茶太好吃了，一下子就把很普通的酒店自助餐比下去了。有30f旋转餐厅和大厅的瀑布餐厅可以选，旋转餐厅有点头晕，还挺热，建议还是瀑布餐厅吧。', '2023-11-06', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766172', '花园酒店，开业38年，经久不衰，大堂永远人庭若市，伴随着悠扬的钢琴声，那么的和谐高雅。此次专门接远道而归的家人，酒店的服务没有过分的热情，确也非常的周到和细致见内涵。房间由原定的红棉套房升级了到了新装修过的房型，床品舒适，床垫偏软，包裹性和承托性很好，一晚恬睡到天明。花园瀑布绿意盎然，锦鲤成群，是饭后的最佳去处。总体入住体验全家满意，值得再来。', '["https://dimg04.c-ctrip.com/images/0231912000cheao36D0F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000chef6024A95_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000ched5zk6D02_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000cheanx02A31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000cheal6y898D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000chec5md9D68_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-30', '红棉双床套房', '套房', '家庭亲子', 173, 5.159055299214529, 0, 0.0, 48, 3.8918202981106265, 9, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店，开业38年，经久不衰，大堂永远人庭若市，伴随着悠扬的钢琴声，那么的和谐', '花园酒店，开业38年，经久不衰，大堂永远人庭若市，伴随着悠扬的钢琴声，那么的和谐高雅。此次专门接远道而归的家人，酒店的服务没有过分的热情，确也非常的周到和细致见内涵。房间由原定的红棉套房升级了到了新装修过的房型，床品舒适，床垫偏软，包裹性和承托性很好，一晚恬睡到天明。花园瀑布绿意盎然，锦鲤成群，是饭后的最佳去处。总体入住体验全家满意，值得再来。', '2023-10-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766178', '这个酒店是我在广州住过最舒服的酒店，位置好，服务好，早餐丰富，前台办理员nike很漂亮，很是温柔，下次还住这里。', '["https://dimg04.c-ctrip.com/images/0233n12000dyi5cfr4344_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000dyi3qj19C46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t12000dyhtpx064CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000dyhytfs5488_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-11', '城央绿意大床房', '大床房', '家庭亲子', 56, 4.04305126783455, 0, 0.0, 32, 3.49650756146648, 7, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '这个酒店是我在广州住过最舒服的酒店，位置好，服务好，早餐丰富，前台办理员nike', '这个酒店是我在广州住过最舒服的酒店，位置好，服务好，早餐丰富，前台办理员nike很漂亮，很是温柔，下次还住这里。', '2024-05-11', 5, '整体满意度');
