INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176617b', '这次和家人到广州旅游，入住了广州花园酒店。在越秀区的花园酒店。正直广交会来往的顾客非常的多，尤其外国人士占了将近50%。虽然入住率很高，但是花园酒店的服务也是跟得上，在广交会期间每层都有服务人员。问好，帮你排忧解难。虽然设施略显成就，但是作为亚洲第二个拥有旋转餐厅的酒店。总体还是非常的不错。', '["https://dimg04.c-ctrip.com/images/0231j12000cfpnc0o787E_R_150_150_R5_Q70_D.webp", "https://dimg04.c-ctrip.com/images/0236512000cfpp1jp4075_R_150_150_R5_Q70_D.webp"]'::jsonb, 4.7, 4, '2023-10-22', '花园双床房', '双床房', '朋友出游', 146, 4.990432586778736, 0, 0.0, 15, 2.772588722239781, 7, '["前台服务", "整体满意度", "公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '这次和家人到广州旅游，入住了广州花园酒店。在越秀区的花园酒店。正直广交会来往的顾', '这次和家人到广州旅游，入住了广州花园酒店。在越秀区的花园酒店。正直广交会来往的顾客非常的多，尤其外国人士占了将近50%。虽然入住率很高，但是花园酒店的服务也是跟得上，在广交会期间每层都有服务人员。问好，帮你排忧解难。虽然设施略显成就，但是作为亚洲第二个拥有旋转餐厅的酒店。总体还是非常的不错。', '2023-10-22', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176617c', '一如既往的好，每次来广州的必选酒店！', '["https://dimg04.c-ctrip.com/images/0236b12000dckopkn6647_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-05', '花园大床房', '大床房', '商务出差', 18, 2.9444389791664403, 0, 0.0, 4, 1.6094379124341005, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '一如既往的好，每次来广州的必选酒店！', '一如既往的好，每次来广州的必选酒店！', '2024-03-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176617d', '花园酒店广州的白金五星酒店，前台服务也是白金五星，处处为宾客着想。岭南花园小桥流水拍照打卡，四楼的酒店博物馆值得参观。', '["https://dimg04.c-ctrip.com/images/0234m12000cr1u4oxC2FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000cr1q3rc8CAE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000cr1t43a6236_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000cr1s4mbAA54_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000cr1t937AE7A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-17', '花园双床房', '双床房', '情侣出游', 59, 4.0943445622221, 0, 0.0, 203, 5.318119993844216, 7, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '花园酒店广州的白金五星酒店，前台服务也是白金五星，处处为宾客着想。岭南花园小桥流', '花园酒店广州的白金五星酒店，前台服务也是白金五星，处处为宾客着想。岭南花园小桥流水拍照打卡，四楼的酒店博物馆值得参观。', '2023-12-17', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176617f', '非常满意的，一如既往的喜欢。瀑布餐厅的早餐不错??整体服务态度真的可以', '["https://dimg04.c-ctrip.com/images/0232c12000d31r9ws83A1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-30', '花园大床房', '大床房', '商务出差', 35, 3.58351893845611, 0, 0.0, 84, 4.442651256490317, 5, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '非常满意的，一如既往的喜欢。瀑布餐厅的早餐不错??整体服务态度真的可以', '非常满意的，一如既往的喜欢。瀑布餐厅的早餐不错??整体服务态度真的可以', '2024-01-30', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766180', '1. 【入住问题】入住排队等了几乎半个小时，从来没见过酒店前台效率这么低的；前台黑脸，没有微笑，不匹配酒店形象。完全是冲着品牌过来的，也住了很多次，反复多次提出过建议，没有任何改进。另外，前台和我们说升级到粤韵，结果发现是红棉，想换成粤韵，在房间打了一个小时电话都没有回复，令人恼火。
2. 【房间状态】红棉很旧，连中国大酒店这种低价酒店都比这个新，有点不可思议。喜欢这家酒店的粤韵，如果不订粤韵，其实这家酒店并没有那么值得居住，宁愿选择旁边的凯宾斯基酒店。我们经常住酒店，觉得花园酒店真的是人员服务匹配不上档次，能有预算选择白天鹅的话，还是选择白天鹅吧。
3. 【服务综评】这家酒店自从因为瀑布餐厅火了之后，管理素质一直跟不上来，甚至有服务人员不尊重客户的情况，不过副总经理和总经理态度尚在，不至于让人失望。但作为超过20年的老客户，真的为这家酒店的管理水平叹息。
ps.第一张和最后一张图是花园酒店，中间几张是旁边那一家酒店，真的对比好大……（??）?其实我们真的很喜欢花园酒店的，毕竟已经开了这么多年，当年做服装生意的时候也是在这里发家的，我们也有情怀，包括身边的朋友，也是有情怀却实在很难为之买单。今天的花园物是人非，除了公共区域之外，其他真的很难夸出口，也不想昧着良心来刷一个好评。??', '["https://dimg04.c-ctrip.com/images/0230m12000clvob1q68E8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231r12000clvujafC987_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000clvvqb444A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000clvnm0cCE97_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000clvo52jF28F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2023-11-20', '花园双床房', '双床房', '其他', 548, 6.3080984415095305, 0, 0.0, 3, 1.3862943611198906, 9, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '1. 【入住问题】入住排队等了几乎半个小时，从来没见过酒店前台效率这么低的；前台', '1. 【入住问题】入住排队等了几乎半个小时，从来没见过酒店前台效率这么低的；前台黑脸，没有微笑，不匹配酒店形象。完全是冲着品牌过来的，也住了很多次，反复多次提出过建议，没有任何改进。另外，前台和我们说升级到粤韵，结果发现是红棉，想换成粤韵，在房间打了一个小时电话都没有回复，令人恼火。
2. 【房间状态】红棉很旧，连中国大酒店这种低价酒店都比这个新，有点不可思议。喜欢这家酒店的粤韵，如果不订粤韵，其实这家酒店并没有那么值得居住，宁愿选择旁边的凯宾斯基酒店。我们经常住酒店，觉得花园酒店真的是人员服务匹配不上档次，能有预算选择白天鹅的话，还是选择白天鹅吧。
3. 【服务综评】这家酒店自从因为瀑布餐厅火了之后，管理素质一直跟不上来，甚至有服务人员不尊重客户的情况，不过副总经理和总经理态度尚在，不至于让人失望。但作为超过20年的老客户，真的为这家酒店的管理水平叹息。
ps.第一张和最后一张图是花园酒店，中间几张是旁边那一家酒店，真的对比好大……（??）?其实我们真的很喜欢花园酒店的，毕竟已经开了这么多年，当年做服装生意的时候也是在这里发家的，我们也有情怀，包括身边的朋友，也是有情怀却实在很难为之买单。今天的花园物是人非，除了公共区域之外，其他真的很难夸出口，也不想昧着良心来刷一个好评。??', '2023-11-20', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766181', '非常满意住在花园酒店，帮我们升级了红棉大床房，房间有些旧但是都能满足需求，服务人员服务都很好，各方面都很满意。', '["https://dimg04.c-ctrip.com/images/0234312000cs6f2apBA35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000cs651eu624F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000cs6cq42CA2A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000cs6682e59A5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000cs6d5kc3898_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000cs6gfljD48C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000cs6c87j7EE7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000cs6c87lC2F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000cs5zcqz0D66_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-22', '城央绿意大床房', '大床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 79, 4.382026634673881, 7, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '非常满意住在花园酒店，帮我们升级了红棉大床房，房间有些旧但是都能满足需求，服务人', '非常满意住在花园酒店，帮我们升级了红棉大床房，房间有些旧但是都能满足需求，服务人员服务都很好，各方面都很满意。', '2023-12-22', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766182', '房间中规中矩，毕竟是中国最早的五星级酒店之二，现代的设施该有的都有。外形和大堂的挑高和巨幅壁画大观园让人震撼，中间藻井一条巨龙盘旋很是带气场，八台电梯足以让贝律铭大师的远见卓识得以认证。没感到岁月的蹉跎，维护得不错??。只是在办理入住和退房的时候稍感迟缓，需要等待多时才能办理好，但酒店不愧为国内五星级的黄埔军校，前台外语溜溜哒，耐心解释入住情况，可能也是办理迟缓的主要原因。住客多为老外，门童为巴基斯坦人，每个楼层都有服务员在电梯口恭候，特别感谢21楼服务员JoJo的热情接待，对问题反馈能及时解决。但酒店服务热线0号有时拨通了无人接听需要改进。小孩的洗漱用品没特别配备，有点遗憾。在旋转餐厅喝下午茶??时碰到了一个美籍华人，他告诉我自己常住花园酒店已有18年，虽然有天河一众奢华酒店，但他情有独钟，也是对酒店服务的认可，非常难得。', '["https://dimg04.c-ctrip.com/images/0236p12000cpmcy6s28C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000cpmc3fzF6C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000cpmcs9v40AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-10', '花园大床房', '大床房', '家庭亲子', 367, 5.908082938168931, 0, 0.0, 100, 4.61512051684126, 9, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '房间中规中矩，毕竟是中国最早的五星级酒店之二，现代的设施该有的都有。外形和大堂的', '房间中规中矩，毕竟是中国最早的五星级酒店之二，现代的设施该有的都有。外形和大堂的挑高和巨幅壁画大观园让人震撼，中间藻井一条巨龙盘旋很是带气场，八台电梯足以让贝律铭大师的远见卓识得以认证。没感到岁月的蹉跎，维护得不错??。只是在办理入住和退房的时候稍感迟缓，需要等待多时才能办理好，但酒店不愧为国内五星级的黄埔军校，前台外语溜溜哒，耐心解释入住情况，可能也是办理迟缓的主要原因。住客多为老外，门童为巴基斯坦人，每个楼层都有服务员在电梯口恭候，特别感谢21楼服务员JoJo的热情接待，对问题反馈能及时解决。但酒店服务热线0号有时拨通了无人接听需要改进。小孩的洗漱用品没特别配备，有点遗憾。在旋转餐厅喝下午茶??时碰到了一个美籍华人，他告诉我自己常住花园酒店已有18年，虽然有天河一众奢华酒店，但他情有独钟，也是对酒店服务的认可，非常难得。', '2023-12-10', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766183', '花园酒店名符其实，地理位置优越，服务品质甚好！', '["https://dimg04.c-ctrip.com/images/0231012000d8sj5s9A4F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000d8seu0l3F98_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-19', '红棉大床套房', '套房', '朋友出游', 23, 3.1780538303479458, 0, 0.0, 107, 4.68213122712422, 5, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店名符其实，地理位置优越，服务品质甚好！', '花园酒店名符其实，地理位置优越，服务品质甚好！', '2024-02-19', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766184', '进入金碧辉煌的大堂，眼睛一亮，一幅镶金壁画《红楼梦》值得赞叹！高大圣诞树烘托节日气氛，前台服务特好，值得称赞。', '["https://dimg04.c-ctrip.com/images/0235r12000cqna9a51057_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000cqmzqqe51D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000cqna9a91400_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000cqn61vsE720_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-15', '红棉双床套房', '套房', '情侣出游', 55, 4.02535169073515, 0, 0.0, 203, 5.318119993844216, 7, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '进入金碧辉煌的大堂，眼睛一亮，一幅镶金壁画《红楼梦》值得赞叹！高大圣诞树烘托节日', '进入金碧辉煌的大堂，眼睛一亮，一幅镶金壁画《红楼梦》值得赞叹！高大圣诞树烘托节日气氛，前台服务特好，值得称赞。', '2023-12-15', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766185', '广州花园酒店环境很优美，入住很舒适，一旦反应问题就会及时处理和解决。', '["https://dimg04.c-ctrip.com/images/0232812000d2urya07E03_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000d2usir24AAF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000d2un9jc35BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-30', '红棉双床套房', '套房', '家庭亲子', 34, 3.555348061489413, 0, 0.0, 10, 2.3978952727983707, 6, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '广州花园酒店环境很优美，入住很舒适，一旦反应问题就会及时处理和解决。', '广州花园酒店环境很优美，入住很舒适，一旦反应问题就会及时处理和解决。', '2024-01-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766186', '房间和服务都非常好，30楼的旋转餐厅非常给力，可以俯瞰整个广州城。健身房和游泳池也很高级，真正是商务家庭出游的好住处', '["https://dimg04.c-ctrip.com/images/0235a12000cpq8r6a7507_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000cpq8r71C219_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000cpq8r7o6E6D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-11', '花园大床房', '大床房', '商务出差', 58, 4.07753744390572, 0, 0.0, 15, 2.772588722239781, 8, '["餐饮设施", "公共设施", "整体满意度"]'::jsonb, '餐饮设施', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间和服务都非常好，30楼的旋转餐厅非常给力，可以俯瞰整个广州城。健身房和游泳池', '房间和服务都非常好，30楼的旋转餐厅非常给力，可以俯瞰整个广州城。健身房和游泳池也很高级，真正是商务家庭出游的好住处', '2023-12-11', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766187', '非常幸运这次能够入住花园酒店，酒店的各方面都给我留下了特别美好的印象。不管是环境还是服务，有其是餐饮，都是一流的。酒店大堂金碧辉煌，花园美轮美奂，各处鲜花环绕，细节都非常完美。太喜欢了！下次来广州一定选择再次入住。', '["https://dimg04.c-ctrip.com/images/0201n12000ccsi6bj905A_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0235f12000ccscv5l7647_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000ccsfrin8247_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000ccsgjc8EB68_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-08', '红棉大床套房', '套房', '家庭亲子', 107, 4.68213122712422, 0, 0.0, 6, 1.9459101490553128, 8, '["整体满意度", "餐饮设施", "公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '非常幸运这次能够入住花园酒店，酒店的各方面都给我留下了特别美好的印象。不管是环境', '非常幸运这次能够入住花园酒店，酒店的各方面都给我留下了特别美好的印象。不管是环境还是服务，有其是餐饮，都是一流的。酒店大堂金碧辉煌，花园美轮美奂，各处鲜花环绕，细节都非常完美。太喜欢了！下次来广州一定选择再次入住。', '2023-10-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766188', '这次出行广州入住了老花园酒店，酒店服务、美食、园林布局果然名不虚传，很有老牌白金五星酒店的风范，较有底蕴。出行前每次致电酒店都有宾至如归的感觉，check in入住当天Viria的专业态度和贴心服务更是留下了深刻印象；瀑布餐厅的景观、荔湾艇的晚餐、行政走廊的早餐都不妨一试。', '["https://dimg04.c-ctrip.com/images/0235e12000ccy2ltx7E33_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000ccyagow6D4C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000ccy8x2cA2B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000ccy873427DD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000ccy2lu10670_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-09', '花园大床房', '大床房', '朋友出游', 137, 4.927253685157205, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '这次出行广州入住了老花园酒店，酒店服务、美食、园林布局果然名不虚传，很有老牌白金', '这次出行广州入住了老花园酒店，酒店服务、美食、园林布局果然名不虚传，很有老牌白金五星酒店的风范，较有底蕴。出行前每次致电酒店都有宾至如归的感觉，check in入住当天Viria的专业态度和贴心服务更是留下了深刻印象；瀑布餐厅的景观、荔湾艇的晚餐、行政走廊的早餐都不妨一试。', '2023-10-09', 5, '前台服务');
