INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176618a', '房间蛮新的，重新装修，不是想象中很老的破五星，大堂特别气派，关键酒店里吃货的天堂，二楼荔湾亭早茶及中晚餐味道很好，三楼桃园馆是米其林餐厅，做的色香味俱全，很细腻，味道很好！一定要品尝，吃了对面广州酒家后觉得还是酒店里好吃！连住三晚！', '["https://dimg04.c-ctrip.com/images/0231y12000cc5dst20A76_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000cc5fo616389_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000cc5bnzh1749_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000cc5a3cp7517_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000cc5fzlf1E4F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000cc5bqkm1AD8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000cc5ckr8CD31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000cc5g3n5692C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000cc5ethg82F3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 116, 4.762173934797756, 0, 0.0, 44, 3.80666248977032, 9, '["餐饮设施", "房间设施", "整体满意度"]'::jsonb, '餐饮设施', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间蛮新的，重新装修，不是想象中很老的破五星，大堂特别气派，关键酒店里吃货的天堂', '房间蛮新的，重新装修，不是想象中很老的破五星，大堂特别气派，关键酒店里吃货的天堂，二楼荔湾亭早茶及中晚餐味道很好，三楼桃园馆是米其林餐厅，做的色香味俱全，很细腻，味道很好！一定要品尝，吃了对面广州酒家后觉得还是酒店里好吃！连住三晚！', '2023-10-05', 5, '餐饮设施');
