INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176618d', '被白金五星给骗了，本来以为是贝聿铭设计的，想来体验一下。然后一进房间就是一股很浓的发霉味道。晚上发现原来一洗澡地板就会漏水。然后房间窗户是封闭式的，很本不通风，所以浓浓的霉味。特别不满意，住到现在最差的五星。', '["https://dimg04.c-ctrip.com/images/0202p12000cck321v2534_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0236y12000cck1jdkF6D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 104, 4.653960350157523, 0, 0.0, 14, 2.70805020110221, 8, '["房间设施", "卫生状况", "整体满意度"]'::jsonb, '房间设施', '卫生状况', '整体满意度', '未知酒店', '未知地点', '匿名', '被白金五星给骗了，本来以为是贝聿铭设计的，想来体验一下。然后一进房间就是一股很浓', '被白金五星给骗了，本来以为是贝聿铭设计的，想来体验一下。然后一进房间就是一股很浓的发霉味道。晚上发现原来一洗澡地板就会漏水。然后房间窗户是封闭式的，很本不通风，所以浓浓的霉味。特别不满意，住到现在最差的五星。', '2023-10-07', 1, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176618e', '太惊艳了，果然没有选错。白金级的服务超赞。除了酒店环境无可挑剔、后花园内的岭南景物让人难忘。入住时送了水果。打卡点后送了文创小物。哈哈哈??开心。', '["https://dimg04.c-ctrip.com/images/0233t12000cjb9j5gC35A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000cjb5nv136C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000cjb85eeEA16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000cjbb14006BB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000cjbebxpDAAC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000cjbe0tr964E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000cjbeu9dBE15_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000cjbbycg6BE2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000cjbgoesAC7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-08', '红棉大床套房', '套房', '家庭亲子', 73, 4.30406509320417, 0, 0.0, 20, 3.044522437723423, 8, '["前台服务", "整体满意度", "周边配套"]'::jsonb, '前台服务', '整体满意度', '周边配套', '未知酒店', '未知地点', '匿名', '太惊艳了，果然没有选错。白金级的服务超赞。除了酒店环境无可挑剔、后花园内的岭南景', '太惊艳了，果然没有选错。白金级的服务超赞。除了酒店环境无可挑剔、后花园内的岭南景物让人难忘。入住时送了水果。打卡点后送了文创小物。哈哈哈??开心。', '2023-11-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176618f', '粤韵双床房非常舒适，64平米，适合一家三口入住，晚上小朋友睡觉后还可以在客厅独立的空间看书或看剧。老牌五星酒店，房间隔断做得很好，隔音效果不错。另外，酒店餐厅也很值得打卡，荔湾亭性价比相对高。', '["https://dimg04.c-ctrip.com/images/0232b12000cazzlocAE89_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-02', '粤韵双床套房', '套房', '家庭亲子', 96, 4.574710978503383, 0, 0.0, 7, 2.079441541679836, 9, '["房间设施", "安静程度", "餐饮设施"]'::jsonb, '房间设施', '安静程度', '餐饮设施', '未知酒店', '未知地点', '匿名', '粤韵双床房非常舒适，64平米，适合一家三口入住，晚上小朋友睡觉后还可以在客厅独立', '粤韵双床房非常舒适，64平米，适合一家三口入住，晚上小朋友睡觉后还可以在客厅独立的空间看书或看剧。老牌五星酒店，房间隔断做得很好，隔音效果不错。另外，酒店餐厅也很值得打卡，荔湾亭性价比相对高。', '2023-10-02', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766190', '各方面都不错', '["https://dimg04.c-ctrip.com/images/0230w12000dd3pmtsCF1D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000dd41a25148D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000dd3xskhD038_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000dd3y7l929D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-07', '花园大床房', '大床房', '商务出差', 6, 1.9459101490553128, 0, 0.0, 5, 1.791759469228055, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '各方面都不错', '各方面都不错', '2024-03-07', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766191', '开了三间房，两间出问题。
第一间：
1.1房卡日期设置错误，无法开房门，下去前台，问我们是否续住的，最后前台解释说日期设置错，是上位前台开卡失误。
1.2入住登记时，已提出要求把三间作关联，因为前台为了快速处理入住，没有告知房卡分别用了谁的信息登记，导致重新开卡时的误会，第一次增加了与前台沟通成本，因为原接待的前台走开了。
第二间：
2.1门锁措施残旧未更换。刷卡进房，门锁显示灯为绿色，但扭动无效，喊了在隔壁的房务员，几次也开不了。
2.2服务响应速度慢。通过楼层电话直拨客服中心，如上反应情况，因为1.2中不知道房卡登记谁的信息，对方也不直接说我信息错误，来回间第二次增加了沟通成本，核对好信息，对方表示让礼宾的同事上来，耐心等待了十来分钟，再次拨打电话，对方表示已看到礼宾员上来找我们，再次耐心等待，才等来礼宾员。
2.3升级房间失误。礼宾员试过门后，主动提出升级房间，并为我们换房卡并带我们去新的房间，我们再再次耐心等待，结果新的房间是双人房，原来房间是大床。礼宾员电话叫房务员拿卡开隔壁房，然后我们再再再次耐心等待，房间没错了。
2.4突**况无备注。礼宾下去换卡给我们，我们婉言拒绝，因为原定外出的时间已耽误很久了，只能晚上我们自己去前台拿卡，让帮忙开好卡就行。晚上回来报了新房号给前台，前台一脸懵，但他并没有表明问题所在，又是一次次无效沟通，他也不停地点击鼠标，我们再再再再次耐心等待，最后我把入住到之前的说了，并主动说了三位入住信息，他才说“难怪和登记的不一样”，第三次增加沟通成本。然而新的房间根本没有为我们预留，也没有任何注明，好在没开出去，不然都不用睡了。
2.5基础专业失误。开好房卡后，前台主动提出带我们到房间，以防其他情况发生。结果房卡刷不开门，显示灯是红色。我们再再再再再次耐心等待前台重新开卡。
最后要赞一下的。唯一一间没有任何问题的，是我爸妈入住的，对大堂工作人员很满意，主动服务意识非常强，房间也很宽敞舒适，对第三次入住花园酒店，仍然是非常满意。真的很谢谢，再再再再再再次感谢', '["https://dimg04.c-ctrip.com/images/0231h12000c7cs670D9E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000c7d14wd4F35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000c7cx9m08E42_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000c7d3aa326D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-09-21', '红棉大床套房', '套房', '家庭亲子', 858, 6.755768921984255, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "退房/入住效率", "客房服务"]'::jsonb, '前台服务', '退房/入住效率', '客房服务', '未知酒店', '未知地点', '匿名', '开了三间房，两间出问题。', '开了三间房，两间出问题。
第一间：
1.1房卡日期设置错误，无法开房门，下去前台，问我们是否续住的，最后前台解释说日期设置错，是上位前台开卡失误。
1.2入住登记时，已提出要求把三间作关联，因为前台为了快速处理入住，没有告知房卡分别用了谁的信息登记，导致重新开卡时的误会，第一次增加了与前台沟通成本，因为原接待的前台走开了。
