最后要赞一下的。唯一一间没有任何问题的，是我爸妈入住的，对大堂工作人员很满意，主动服务意识非常强，房间也很宽敞舒适，对第三次入住花园酒店，仍然是非常满意。真的很谢谢，再再再再再再次感谢', '2023-09-21', 1, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766192', '目前住过广州最有特色的酒店，整个酒店就像一间巨大的博物馆??就很有历史底蕴，酒店的外国友人也很多。本来以为这么老的酒店，只是住个特色，没想到真正住下来很惊喜。床品软硬适中，让人一躺下来就想睡觉。', '["https://dimg04.c-ctrip.com/images/0233f12000c7ruvp46DC5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000c7s31fu2F57_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000c7s3kdwF242_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000c7rymqkAC63_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000c7s2s215E1B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000c7s32emD380_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000c7s1jgtA717_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000c7s2geq14B1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000c7rsy6y540B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-22', '红棉大床套房', '套房', '家庭亲子', 97, 4.584967478670572, 0, 0.0, 4, 1.6094379124341005, 8, '["整体满意度", "房间设施"]'::jsonb, '整体满意度', '房间设施', NULL, '未知酒店', '未知地点', '匿名', '目前住过广州最有特色的酒店，整个酒店就像一间巨大的博物馆??就很有历史底蕴，酒店', '目前住过广州最有特色的酒店，整个酒店就像一间巨大的博物馆??就很有历史底蕴，酒店的外国友人也很多。本来以为这么老的酒店，只是住个特色，没想到真正住下来很惊喜。床品软硬适中，让人一躺下来就想睡觉。', '2023-09-22', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766193', '首先我想说.一直出差来广州.住过很多家酒店.但是对于我这个挑剔的人来说.我很喜欢花园酒店.品牌有文化底蕴.尤其是吃早饭下午茶的瀑布酒店很漂亮.装修风格干净典雅.服务也很好.让你心里舒服.停车在隔壁的地下停车场也很方便.总之希望继续保持哦.以后只要来广州就是花园酒店！', '["https://dimg04.c-ctrip.com/images/0230e12000c5h2u95A728_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000c5grlf4CE05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000c5h4x3aA0E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000c5gtqasC300_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000c5gtqau9F82_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-15', '花园大床房', '大床房', '商务出差', 133, 4.897839799950911, 0, 0.0, 55, 4.02535169073515, 8, '["整体满意度", "餐饮设施", "公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '首先我想说.一直出差来广州.住过很多家酒店.但是对于我这个挑剔的人来说.我很喜欢', '首先我想说.一直出差来广州.住过很多家酒店.但是对于我这个挑剔的人来说.我很喜欢花园酒店.品牌有文化底蕴.尤其是吃早饭下午茶的瀑布酒店很漂亮.装修风格干净典雅.服务也很好.让你心里舒服.停车在隔壁的地下停车场也很方便.总之希望继续保持哦.以后只要来广州就是花园酒店！', '2023-09-15', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766194', '前台Katherine、Gtillian小姐姐服务态度非常不错，专门给她的好评。交通便利，停车方便!停车场很大，还是免费停车场。房间很大，设施也很齐全。房间还送的有矿泉水。前台小姐姐估计是考虑我要休养，给我升级了房型一房一厅高楼层真是太舒服了！床上用品洗的也很干净，床垫软软的，睡起来很舒服。中央空调很凉快。有什么需要，给前台打电话，都能解决!前台小姐姐还详细的讲解了吗无线网，早餐种类等!真的很好！', '["https://dimg04.c-ctrip.com/images/0231n12000c4hb8yn5177_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000c4hg3ez3316_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000c4he5ug2B02_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-13', '红棉大床套房', '套房', '其他', 200, 5.303304908059076, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "交通便利性", "房间设施"]'::jsonb, '前台服务', '交通便利性', '房间设施', '未知酒店', '未知地点', '匿名', '前台Katherine、Gtillian小姐姐服务态度非常不错，专门给她的好评。', '前台Katherine、Gtillian小姐姐服务态度非常不错，专门给她的好评。交通便利，停车方便!停车场很大，还是免费停车场。房间很大，设施也很齐全。房间还送的有矿泉水。前台小姐姐估计是考虑我要休养，给我升级了房型一房一厅高楼层真是太舒服了！床上用品洗的也很干净，床垫软软的，睡起来很舒服。中央空调很凉快。有什么需要，给前台打电话，都能解决!前台小姐姐还详细的讲解了吗无线网，早餐种类等!真的很好！', '2023-09-13', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766195', '设施：一流和先进。
卫生：干净。
环境：优美、静谧。
