INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661af', '宾客服务kristy金牌导游的服务非常好，人很热情声音也好听。酒店席梦思的床住的也很舒服，掀开一看是席梦思和花园的联名款，真的很不错', '["https://dimg04.c-ctrip.com/images/0235k12000c7zavmbB084_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-23', '红棉大床套房', '套房', '家庭亲子', 66, 4.204692619390966, 0, 0.0, 4, 1.6094379124341005, 8, '["客房服务", "房间设施"]'::jsonb, '客房服务', '房间设施', NULL, '未知酒店', '未知地点', '匿名', '宾客服务kristy金牌导游的服务非常好，人很热情声音也好听。酒店席梦思的床住的', '宾客服务kristy金牌导游的服务非常好，人很热情声音也好听。酒店席梦思的床住的也很舒服，掀开一看是席梦思和花园的联名款，真的很不错', '2023-09-23', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661b0', '酒店很棒，服务也很棒，很多外宾、很多空姐空少都入住这家酒店，看到每位工作人员都能游刃有余的与外宾们沟通办理业务，大气高水准。房间里有两个洗漱台和两台电视，真是太方便了，还配备了胶囊咖啡机，入住时按人数赠送了酒吧体验券，可惜带着娃不方便，没能体验到，酒店里的花园和博物馆深得娃的喜爱，退房时还送了小礼品，开心。早餐在一楼的瀑布餐厅或二楼荔湾亭，一楼大多是外宾，西式早餐居多，二楼有中式早餐，一楼排队人太多了，工作人员引导至二楼用餐，餐食品种不算多，将就随便填些肚子，中午去顺德再吃丰盛点吧。对了，晚餐在荔湾亭，叉烧真是太好吃了，粥也很美味，地道的粤菜很棒。', '["https://dimg04.c-ctrip.com/images/0232612000bty7n528D09_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000bty993r22F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000btye7ugCBD2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000bty6yi86986_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000btycmpd5A17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000btycnsj799A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000bty8dysB2B0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000btybtz064E3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-05', '花园双床房', '双床房', '家庭亲子', 277, 5.627621113690637, 0, 0.0, 23, 3.1780538303479458, 9, '["房间设施", "前台服务", "餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店很棒，服务也很棒，很多外宾、很多空姐空少都入住这家酒店，看到每位工作人员都能', '酒店很棒，服务也很棒，很多外宾、很多空姐空少都入住这家酒店，看到每位工作人员都能游刃有余的与外宾们沟通办理业务，大气高水准。房间里有两个洗漱台和两台电视，真是太方便了，还配备了胶囊咖啡机，入住时按人数赠送了酒吧体验券，可惜带着娃不方便，没能体验到，酒店里的花园和博物馆深得娃的喜爱，退房时还送了小礼品，开心。早餐在一楼的瀑布餐厅或二楼荔湾亭，一楼大多是外宾，西式早餐居多，二楼有中式早餐，一楼排队人太多了，工作人员引导至二楼用餐，餐食品种不算多，将就随便填些肚子，中午去顺德再吃丰盛点吧。对了，晚餐在荔湾亭，叉烧真是太好吃了，粥也很美味，地道的粤菜很棒。', '2023-08-05', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661b2', '真的太喜欢这家酒店了，不愧是广州的门面酒店。大堂很大气，房间很干净，床品很舒适，打扫人员和服务员都很nice，文创小羊羊真的太可爱了～早餐在瀑布餐厅，我觉得也很不错。酒店自带博物馆还有好几家米其林入选餐厅。门口的就是地铁站，交通非常方便。最近泳池维修中，按摩池和桑拿可以用。唯一的不足，最近白天有修路工程，晚上倒是不影响～大堂还可以免费寄明信片！下次来还住这边！爱～', '["https://dimg04.c-ctrip.com/images/0233a12000bqhzfb8B09E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000bqht7tq1CB2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-24', '花园双床房', '双床房', '家庭亲子', 183, 5.214935757608986, 0, 0.0, 10, 2.3978952727983707, 9, '["整体满意度", "交通便利性", "卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况', '未知酒店', '未知地点', '匿名', '真的太喜欢这家酒店了，不愧是广州的门面酒店。大堂很大气，房间很干净，床品很舒适，', '真的太喜欢这家酒店了，不愧是广州的门面酒店。大堂很大气，房间很干净，床品很舒适，打扫人员和服务员都很nice，文创小羊羊真的太可爱了～早餐在瀑布餐厅，我觉得也很不错。酒店自带博物馆还有好几家米其林入选餐厅。门口的就是地铁站，交通非常方便。最近泳池维修中，按摩池和桑拿可以用。唯一的不足，最近白天有修路工程，晚上倒是不影响～大堂还可以免费寄明信片！下次来还住这边！爱～', '2023-07-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661b3', '房间宽敞明亮，服务贴心周到，停车方便，交通便利，早餐丰盛，环境优雅。
